(28, 'Mary Ann Sarlatan', 'Contact Us Form', '2024-12-19 02:08:15', '<div class=\"form_table\" style=\"width:700px; height:auto; font-size:12px; color:#333333; letter-spacing:1px; line-height:20px; margin: 0 auto;\">\n			<div style=\"border:8px double #c3c3d0; padding:12px;\">\n			<div align=\"center\" style=\"color:#990000; font-style:italic; font-size:20px; font-family:Arial; margin:bottom: 15px;\">(Contact Us Form)</div>\n\n			<table width=\"90%\" cellspacing=\"2\" cellpadding=\"5\" align=\"center\" style=\"font-family:Verdana; font-size:13px\">\n				<tr><td><b>First Name</b>:</td> <td>Mary Ann</td></tr><tr><td><b>Last Name</b>:</td> <td>Sarlatan</td></tr><tr><td><b>Address</b>:</td> <td>Tuburan, Cebu Philippines</td></tr><tr><td><b>Email Address</b>:</td> <td>maryann@springhive.org</td></tr><tr><td><b>Phone</b>:</td> <td>1-209-266-2388</td></tr><tr><td><b>Question or Comment</b>:</td> <td>Hi there,\r\n\r\nWe hope you&#039;re well. I&#039;m Mary Ann, and I&#039;m a Sales Representative at Springhive Inc. We truly admire the charitable work your organization does for the community.\r\n\r\nWe believe we can support your mission by enhancing your online presence. Hereâs how we can help:\r\n\r\nWebsite Design &amp; Development\r\n\r\n    We create user-friendly, professional websites tailored to your needs.\r\n\r\nSEO (Search Engine Optimization)\r\n\r\n    We improve your websiteâs visibility on search engines to reach more donors and volunteers.\r\n\r\nWebsite Hosting and Maintenance\r\n\r\n    We ensure your site is fast, secure, and always up-to-date.\r\n\r\nSocial Media Management\r\n\r\n    We develop engaging content to grow your online community and boost engagement.\r\n\r\nMarketing Videos\r\n\r\n    We produce compelling videos to showcase your work and inspire more support.\r\n\r\nTo start, weâd love to offer you a free website audit. This will help identify strengths and areas for improvement.\r\n\r\nInterested? Letâs schedule a time to review the audit and discuss how we can help your charity grow.\r\n\r\nWarm regards,\r\n\r\nMary Ann Sarlatan\r\nSales Representative\r\nSpringhive Inc.</td></tr>\n			</table>\n\n			</div>\n			</div>', 'new', 'inbox', '', '0000-00-00 00:00:00'),
(29, 'Teena Paz', 'Contact Us Form', '2025-01-26 01:14:23', '<div class=\"form_table\" style=\"width:700px; height:auto; font-size:12px; color:#333333; letter-spacing:1px; line-height:20px; margin: 0 auto;\">\n			<div style=\"border:8px double #c3c3d0; padding:12px;\">\n			<div align=\"center\" style=\"color:#990000; font-style:italic; font-size:20px; font-family:Arial; margin:bottom: 15px;\">(Contact Us Form)</div>\n\n			<table width=\"90%\" cellspacing=\"2\" cellpadding=\"5\" align=\"center\" style=\"font-family:Verdana; font-size:13px\">\n				<tr><td><b>First Name</b>:</td> <td>Teena</td></tr><tr><td><b>Last Name</b>:</td> <td>Paz</td></tr><tr><td><b>Address</b>:</td> <td>4466 Southside Lane</td></tr><tr><td><b>Email Address</b>:</td> <td>teena.paz88@gmail.com</td></tr><tr><td><b>Phone</b>:</td> <td>3237661183</td></tr><tr><td><b>Question or Comment</b>:</td> <td>Hey there, I came across your website and was impressedâgreat work!\r\n\r\nI know your time is valuable, so Iâll be brief.\r\n\r\nAI is essential for business growth, and many owners struggle to know where to startâthatâs why Iâm here to help.\r\n\r\nWeâve created two guides called AI For Entrepreneurs and Smarter with AI, normally priced at $29 each, and we&#039;re offering it to you for free. Inside, youâll discover:\r\n\r\n    + How to quickly increase your business/website revenue.\r\n    + A simple framework for incorporating AI into your business.\r\n    + Proven strategies to boost productivity and save time.\r\n    + Expert tips to get results, whether you&#039;re just starting or well-established.\r\n\r\nRemember, this is absolutely free and will cost you nothing! \r\n\r\nWould you like a free copy?\r\n\r\nGet yor guide here: http://aibusinessmastery.pro\r\n\r\nIâm confident itâll be a game-changer for you, and Iâd love to hear how it works for your business!\r\n\r\nBest regards</td></tr>\n			</table>\n\n			</div>\n			</div>', 'new', 'inbox', '', '0000-00-00 00:00:00'),
