(152, 'widget_classictextwidget', 'a:8:{i:2;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:171:\"<ul>\r\n<li>Email Us: <a href=\"mailto:Lmuiruri@fountainwisdom.org\">Lmuiruri@fountainwisdom.org</a> </li>\r\n<li>Feel free to talk to us! <mark>617-528-8672</mark> </li>\r\n</ul>\";s:6:\"filter\";b:0;}i:3;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:355:\"<h2>Get In Touch With Us</h2>\r\n<p>To help or learn more, donât hesitate to message us.</p>\r\n\r\n<ul>\r\n<li class=\"ftr_address\"> <address>390 Main Street, Suite 445\r\nWorcester, MA 01608</address> </li>\r\n<li class=\"ftr_contact\">Phone: <mark>617-528-8672</mark>\r\nEmail: <a href=\"mailto:Lmuiruri@fountainwisdom.org\">Lmuiruri@fountainwisdom.org</a> </li>\r\n</ul>\";s:6:\"filter\";b:0;}i:4;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:134:\"<h2>Volunteer Now!</h2>\r\n<p>Sponsor us and be acknowledged for your contribution.</p>\r\n<a href=\"nonprofit-organization-volunteer\"></a>\";s:6:\"filter\";b:0;}i:5;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:142:\"<h2>Sign Up As a Sponsor</h2>\r\n<p>Sponsor us and be acknowledged for your contribution.</p>\r\n<a href=\"nonprofit-organization-sponsorship\"></a>\";s:6:\"filter\";b:0;}i:6;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:239:\"<div class=\"bnr_info\">\r\n<h2>Support for Better \r\n<span>Education in Karia</span> </h2>\r\n<p>Eliminating poverty in Karia village through better education</p>\r\n<a href=\"nonprofit-organization-donate\">Make a <span>Donation</span> </a>\r\n</div>\";s:6:\"filter\";b:0;}i:7;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:491:\"<div class=\"btm2_info\">\r\n<h2>Our Mission <span>Statement</span> </h2>\r\n<p>To improve learning in Karia primary school through upgrading dilapidated classrooms, building a library and computer lab, providing proper students desks and up-to-date learning materials, and improving sport fields. Also, we plan to build a community library to benefit village members who are not in school. \r\n <span> <a href=\"nonprofit-organization-about-us#mission\">[ About Us &rsaquo; ]</a> </span> </p>\r\n</div>\";s:6:\"filter\";b:0;}i:8;a:3:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:131:\"<h2>Support Our Advocacy</h2>\r\n<p>Hereâs what you can do to help.</p>\r\n<a href=\"nonprofit-organization-support-our-advocacy\"></a>\";s:6:\"filter\";b:0;}s:12:\"_multiwidget\";i:1;}', 'yes'),
