(4630, '_transient_master-slider-notice-info-ms-notice-info-global', 'a:9:{s:10:\"remote_url\";s:82:\"http://cdn.averta.net/project/masterslider/free/info/ms-notice-content-global.html\";s:8:\"beta_url\";s:87:\"http://cdn.averta.net/project/masterslider/free/info/ms-notice-content-global-beta.html\";s:8:\"revision\";s:0:\"\";s:11:\"first_delay\";s:0:\"\";s:2:\"id\";s:21:\"ms-notice-info-global\";s:7:\"enabled\";b:0;s:7:\"content\";s:2426:\"<div class=\"msp-banner-media msp-notice-wrapper\" style=\"\n		margin-bottom:10px; text-align:left;\n		position:relative;\n		background:#129ff7 url(https://www.masterslider.com/wp-content/uploads/sites/5/2013/10/upgrade-depicter-master.jpg) right center no-repeat;\n		background-size:auto;\n		height: 220px;\">\n	<div class=\"ms-notice-inner\" style=\"padding:17px 20px 15px 33px;box-sizing:border-box;height:100%;\">\n		<h3 style=\"color:#fff;font-size: 32px;line-height:34px; margin:5px 0 0 0;letter-spacing:0; text-align:left;\">Thanks for Using <span style=\"text-decoration:underline;\">Master Slider</span></h3>\n		<h4 style=\"color:#fff;font-size: 28px;line-height: 34px;margin:7px 0 0 0;text-align:left;\">Get Exciting New Slider Features Today for Free!</h4>\n		<p style=\"color:#fff;font-size: 12px;line-height: 18px;margin: 13px 0 14px;max-width: 500px;text-align:left;\">Master Slider developers have created an even better and free slider plugin just for you. Say hello to Depicter!</p>\n		<a class=\"ms-notice-primary-btn\" href=\"plugin-install.php?s=Depicter%2520Slider%2520-%2520Responsive&tab=search&type=term\" target=\"_blank\" style=\"padding: 9px 14px;font-size: 12px;background-color:#222;color:#fafafa;border-radius: 25px;margin-top:25px;float:left;margin: 0 8px 0 1px;text-decoration: none;\">Activate Depicter</a>\n		<a class=\"ms-notice-secondary-btn\" href=\"https://depicter.com/?utm_source=ms-dashboard&utm_medium=banner&utm_campaign=ms-to-dp-migration\" target=\"_blank\" style=\"padding: 7px 13px;font-size: 12px;background-color:transparent;color:#fafafa;border-radius:25px;margin-top:25px;float:left;margin:0 20px 0 1px;text-decoration:none; border:2px solid #fff;\">Show Me More</a>\n		<a href=\"#\" class=\"ms-dismiss-btn notice-dismiss ms-notice-dismiss ms-close-notice\" data-id=\"ms-notice-info-global\" style=\"\n			position:absolute;\n			top:8px;\n			right:8px;\n			border-radius:50%;\n			font-size: 12px;\n			color: #fff;\n			padding:0;\n			text-align:center;\n			text-decoration:none;\n			\"><span class=\"screen-reader-text\">Dismiss this notice.</span></a>\n	</div>\n</div>\n<style>\n.ms-notice-primary-btn:hover{\n\n}\n.ms-notice-secondary-btn:hover{\n\n}\n.notice-dismiss:before{\n	font-size:20px;\n	color:#bbb;\n}\n.notice-dismiss:hover:before{\n	color:#fff;\n}\n@media screen and (max-width: 1620px) {\n	.ms-notice-inner{\n		background-color:#129ff79c;\n	}\n}\n@media screen and (max-width: 1200px) {\n	.ms-notice-inner{\n		background-color:#129ff7cf;\n	}\n}\n</style>\";s:12:\"delay_passed\";b:1;s:5:\"debug\";a:5:{i:0;s:3:\"1.3\";i:1;s:3:\"1.4\";i:2;s:35:\"Due - Now: Passed 124069002 seconds\";i:3;s:19:\"Previous revision: \";i:4;s:17:\"Remote revision: \";}}', 'no'),
