//s.w.org/favicon.ico?2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"WordPress News\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"https://wordpress.org/news\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.6 Beta 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://wordpress.org/news/2024/06/wordpress-6-6-beta-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 11 Jun 2024 16:26:15 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=17355\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:342:\"WordPress 6.6 Beta 2 is here! Please download and test it. This beta version of the WordPress software is under development. Please do not install, run, or test this version of WordPress on production or mission-critical websitesâyou risk unexpected results if you do. Instead, test Beta 2 on a local site or a testing environment [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"marybaum\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7673:\"\n<p><br>WordPress 6.6 Beta 2 is here! Please download and test it.</p>\n\n\n\n<p id=\"block-79834dd4-c99a-477a-b722-091806a32976\"><strong>This beta version of the WordPress software is under development. </strong>Please do not install, run, or test this version of WordPress on production or mission-critical websitesâyou risk unexpected results if you do.</p>\n\n\n\n<p id=\"block-aa4b335e-b1a2-4904-a68c-c3e73e574386\">Instead, test Beta 2 on a local site or a testing environment in any of these four ways:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><th>Plugin</th><td>Install and activate the <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> plugin on a WordPress install. (Select the âBleeding edgeâ channel and âBeta/RC Onlyâ stream).</td></tr><tr><th>Direct Download</th><td>Download the <a href=\"https://wordpress.org/wordpress-6.6-beta2.zip\">Beta 2 version (zip)</a> and install it on a WordPress website.</td></tr><tr><th>Command Line</th><td>Use this <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> command:<br><code>wp core update --version=6.6-beta2</code></td></tr><tr><th>WordPress Playground</th><td>Use a <a href=\"https://playground.wordpress.net/#{%20%22preferredVersions%22:%20{%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20},%20%22features%22:%20{%20%22networking%22:%20true%20},%20%22steps%22:%20[%20{%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20}%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20},%20%22options%22:%20{%20%22activate%22:%20false%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20}%20]%20}\">6.6 Beta 2 WordPress Playground instance</a> to test the software directly in your browser. This might be the easiest way everâno separate sites, no setup. Just click and go!&nbsp;</td></tr></tbody></table><figcaption class=\"wp-element-caption\">Three ways to test WordPress Beta 2.</figcaption></figure>\n\n\n\n<p id=\"block-7e6a92e6-dba7-4f69-9226-f4dcab4a0b91\">The target release date for WordPress 6.6 is <strong>July 16, 2024</strong>. Your help testing Beta and RC versions over the next five weeks is vital to making sure the final release is everything it should be: stable, powerful, and intuitive.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"block-aebce12b-08f8-40a7-9fe6-5a08f75d2254\">If you find an issue</h2>\n\n\n\n<p id=\"block-b9e58289-f6cb-4bdd-85a1-eb8d9a704ae4\">If you run into an issue, please share it in the&nbsp;<a href=\"https://wordpress.org/support/forum/alphabeta/\">Alpha/Beta area</a>&nbsp;of the support forums. If you are comfortable submitting a reproducible bug report, you can do so&nbsp;<a href=\"https://core.trac.wordpress.org/newticket\">via WordPress Trac</a>. You can also check your issue against a list of&nbsp;<a href=\"https://core.trac.wordpress.org/tickets/major\">known bugs</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The bug bounty doubles in the beta period</h2>\n\n\n\n<p>The WordPress community sponsors a&nbsp;<a href=\"https://make.wordpress.org/security/2024/06/04/wordpress-6-6-is-coming/\">financial reward for reporting new, unreleased security vulnerabilities.</a>&nbsp;That reward doubles between Beta 1, which landed June 4, and the final Release Candidate (RC) that will happen July 9. Please follow the projectâs responsible-disclosure practices detailed on this&nbsp;<a href=\"https://hackerone.com/wordpress\">HackerOne page</a>&nbsp;and in this&nbsp;<a href=\"https://wordpress.org/about/security/\">security white paper</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The work continues</h2>\n\n\n\n<p><strong>Catch up with what&#8217;s new in 6.6:</strong> <a href=\"https://wordpress.org/news/2024/06/wordpress-6-6-beta-1/\" data-type=\"post\" data-id=\"17289\">check out the Beta 1 announcement for the highlights.</a></p>\n\n\n\n<p>Beta 2 packs in more than 50 updates to the Editor since the Beta 1 release, including 40+ <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=02%2F14%2F2024..02%2F19%2F2024&amp;milestone=6.5&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">tickets for WordPress core</a>:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/trunk?since=2024-06-04&amp;until=2024-06-07&amp;before=c7f51bdbe10bec0c0ab7f987a3f01caaa717c1db+70\" data-type=\"link\" data-id=\"https://github.com/WordPress/gutenberg/commits/wp/6.5?since=2024-02-14&amp;until=2024-02-20\">GitHub commits for 6.6</a> since June 4</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?changetime=06%2F04%2F2024..06%2F11%2F2024&amp;resolution=fixed&amp;milestone=6.6&amp;max=1000&amp;col=id&amp;col=summary&amp;col=type&amp;col=milestone&amp;col=owner&amp;col=status&amp;col=priority&amp;order=priority\">Closed Trac tickets</a> since June 4</li>\n</ul>\n\n\n\n<p>The beta cycle is all about fixing the bugs you find in testing. Thanks again for this vitally important contribution to WordPress! </p>\n\n\n\n<p class=\"has-text-align-right is-style-default\"><em>Props to <a href=\'https://profiles.wordpress.org/priethor/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>priethor</a>, <a href=\'https://profiles.wordpress.org/dansoschin/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>dansoschin</a>, <a href=\'https://profiles.wordpress.org/davidb/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>davidb</a>, <a href=\'https://profiles.wordpress.org/atachibana/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>atachibana</a>, <a href=\'https://profiles.wordpress.org/meher/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>meher</a>, <a href=\'https://profiles.wordpress.org/webcommsat/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>webcommsat</a>, and <a href=\'https://profiles.wordpress.org/juanmaguitar/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>juanmaguitar</a> for collaboration and review.</em></p>\n\n\n\n<h2 class=\"wp-block-heading\">A Beta 2 haiku</h2>\n\n\n\n<p>Testing is vital:<br>It makes everything better.<br>Let&#8217;s find all the bugs!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17355\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:61:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"WP Briefing: Episode 81: Itâs your first WordCamp? Welcome!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://wordpress.org/news/2024/06/episode-81-its-your-first-wordcamp-welcome/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 10 Jun 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"wp-briefing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=17352\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:373:\"Get ready to dive into the vibrant world of WordCamps with this special episode of the WordPress Briefing, hosted by Josepha Haden Chomphosy! This episode is designed for first-time attendees; weâll explore what to expect, from Contributor Day activities to mastering the art of socializing and networking. Whether youâre aiming to contribute to the WordPress [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:51:\"https://wordpress.org/news/files/2024/06/WPB081.mp3\";s:6:\"length\";s:1:\"0\";s:4:\"type\";s:0:\"\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:19398:\"\n<p>Get ready to dive into the vibrant world of WordCamps with this special episode of the WordPress Briefing, hosted by Josepha Haden Chomphosy! This episode is designed for first-time attendees; weâll explore what to expect, from Contributor Day activities to mastering the art of socializing and networking. Whether youâre aiming to contribute to the WordPress community or simply looking to make new connections, this episode will help you navigate your first WordCamp with confidence and excitement. Join us for a fun and informative guide to ensure youâre prepared and energized for all the activities these dynamic events have to offer.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Host:&nbsp;<a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a><br>Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br>Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br>Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a><br>Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://asia.wordcamp.org/\">WordCamp Asia</a></li>\n\n\n\n<li><a href=\"https://europe.wordcamp.org/\">WordCamp Europe</a></li>\n\n\n\n<li><a href=\"https://us.wordcamp.org/\">WordCamp US</a></li>\n\n\n\n<li><a href=\"https://events.wordpress.org/upcoming-events/filtered/type/wordcamp/\">Upcoming Smaller WordCamps</a></li>\n\n\n\n<li><a href=\"https://learn.wordpress.org/\">Learn WordPress</a><br><strong>Small List of Big Things</strong>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://www.surveymonkey.com/r/9T3ZFSB\" target=\"_blank\" rel=\"noreferrer noopener\">Gender Equality in WordPress Businesses Survey</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2025/dates-and-venue-revealed/\" target=\"_blank\" rel=\"noreferrer noopener\">WordCamp Asia 2025: Dates and Venue Revealed</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/contribute/\" target=\"_blank\" rel=\"noreferrer noopener\">Try the Contributor Wizard Questionnaire</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/updates/2024/05/23/five-for-the-future-program-updates-may-2024/\" target=\"_blank\" rel=\"noreferrer noopener\">Five for the Future Program Updates: May 2024</a></li>\n</ul>\n</li>\n\n\n\n<li>Have a question youâd like answered? Submit them to&nbsp;<a href=\"mailto:wpbriefing@WordPress.org\">WPBriefing@WordPress.org</a>.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcript</h2>\n\n\n\n<span id=\"more-17352\"></span>\n\n\n\n<p>[00:00:00] <strong>Josepha:</strong> Hello, everyone, and welcome to the WordPress Briefing, the podcast where you can catch quick explanations of the ideas behind the WordPress open source project, some insight into the community that supports it, and get a small list of big things coming up in the next two weeks. I&#8217;m your host, Josepha Haden Chomphosy. Here we go.</p>\n\n\n\n<p>[00:00:28] (Intro Music)Â </p>\n\n\n\n<p>[00:00:40] <strong>Josepha:</strong> A pivotal moment in my WordPress journey was when someone invited me to a WordCamp. I was sort of aware of WordPress, but certainly not aware of the community or the ways of open source. And when I look back, there were a few things I wish I had known going in. I am, of course, an unapologetic extrovert and therefore unstoppable at events, but if you are headed to your first WordCamp and are feeling a little nervous or confused, then pop in some earbuds because the next 10 minutes are for you.</p>\n\n\n\n<p>[00:01:11] <strong>Josepha:</strong> We&#8217;re going to first take a look at some basic tactical things about WordCamps, and then I&#8217;m going to tell you a few, like, human things about being a human going to events. If you&#8217;re a dog going to these events, I think that your prep is different, but also that is not my area of expertise. So the first thing, some tactical stuff about going to WordCamps. All of this happens before you even get in the front door. And so this is stuff that you can do in the comfort of your own home, on your own time, using your own computer. If you&#8217;ve got questions, you&#8217;ve got a search engine nearby to take some quick searches. Make sure you know what you&#8217;re talking about.</p>\n\n\n\n<p>But first things first, the shape of a WordCamp. All WordCamps have at least one day of talks, one social event, and sponsors to connect to. Some also have extra events that you need to sign up for, like Contributor Days, workshops, things like that. But we&#8217;ll start with the main event, right? We&#8217;re going to start with the day of talks and things.</p>\n\n\n\n<p>[00:02:09] <strong>Josepha:</strong> So when we&#8217;re looking at the main event of a WordCamp, what you should do is you should head to the WordCamp&#8217;s website and check out the schedule. I suggest that you plan for two, maybe three things that you might want to learn and look around at the schedule to see if there are any presenters or presentations that look like they fit those things that you think you might want to learn. Because if it&#8217;s not working for you, if it&#8217;s not teaching you something, then you don&#8217;t necessarily need to be in that one. Even if you&#8217;re not sure about a session a talk that you&#8217;re planning to go to, I recommend that you stop by, and then if you find out that it&#8217;s not for you, you can leave again.  That&#8217;s fine. But I do encourage you to go to at least one thing that feels a little bit outside of your comfort zone. Even if you feel lost right now. It at least gives you an idea of what to search for once you do get to that point. I would never have known the things to search for early on in my learning of WordPress without going to at least one or two sessions that were just way over my head.Â </p>\n\n\n\n<p>[00:03:14] <strong>Josepha:</strong> Second thing is don&#8217;t forget to check when lunch is available. And if you have dietary restrictions, let them know ahead of time. I realize this sounds silly, and I don&#8217;t know about you, but I can&#8217;t focus when I&#8217;m hungry. But also, it&#8217;s really a great, low-stakes networking time, and I think one of the overlooked networking times as well. I mean, everyone&#8217;s gotta eat, right? And it&#8217;s easier to strike up a conversation over a meal than just out of thin air or, you know, in the middle of a presentation when you&#8217;re supposed to be listening to a talk. So yeah, check out when lunch is happening! And yeah, make a friend or two, sit down at a table, and ask somebody what they&#8217;re doing with WordPress and how long they&#8217;ve been doing it.</p>\n\n\n\n<p>And the third thing that I would recommend that you do when you&#8217;re looking at kind of the main event for a WordCamp is to schedule in time to wander around and meet the event sponsors. They are all experts in some WordPress problem or other, so probably they have a solution to a problem that you have got. But they&#8217;re also how we keep our prices super low, so even if you have no problems or you think you have no problems. Still, check them out. They&#8217;re also staffed with wonderful people that are building really cool stuff with WordPress and so you might just get some inspiration out there.Â </p>\n\n\n\n<p>[00:04:28] <strong>Josepha:</strong> Now for the side events.</p>\n\n\n\n<p>So the side events, we&#8217;re going to kind of start close to the main event and work our way out. So you&#8217;ve got generally three types of side events if you don&#8217;t count the networking things, which, in this case, I&#8217;m not. But just know that almost every WordCamp has some networking event, either an after-party or, like, a happy hour, a social that happens before the event.</p>\n\n\n\n<p>You&#8217;ll get emails about those if you have signed up for updates on the website. Also, you can look on the website directly. Just check out the schedule. Always go to those. The networking is the best at a WordCamp. But the side eventsâwe&#8217;re talking about specific types. Like I said, we&#8217;re going to start close and work our way out.</p>\n\n\n\n<p>[00:05:11] <strong>Josepha:</strong> So, workshops. These are just what they sound like. They&#8217;re classroom-style opportunities to practice the things you&#8217;ve learned at meetup events or on learn.WordPress.org, depending on how you found your way to this WordCamp. They mostly happen during the WordCamp itself. in a separate track, and there are like stacks of workshops in that track in that series of sessions. But a lot of them do require preregistration simply so that the trainer has an idea of how many people to expect. Again, if you get in the workshop and it&#8217;s way over your head, you feel like you absolutely cannot get it done, you&#8217;re always welcome to leave and check out some other area. But, in general, the workshops that we have WordCamps are pretty solid.</p>\n\n\n\n<p>So a little bit further removed from that are our Youth and Teen Days. So this is more of an event series that is specifically designed for teens or kids who are trying to learn more about WordPress and other related business and entrepreneurial topics. It&#8217;s kind of a catch all but also has a lot of WordPress content in it. They have age limits, of course, and require separate registration for safety and planning purposes both. And those, in general, are either half-day during the WordCamp itself or a full-day during that WordCamp. </p>\n\n\n\n<p>[00:06:32] <strong>Josepha:</strong> Which brings us then to the big one, the major side event. This is a full-day side event called Contributor Day. If your WordCamp has a Contributor Day, it will happen either the day before or the day after the WordCamp itself. It is an entire day where attendees come together to learn how to contribute to the future of the WordPress open source project. Now, if you are listening to this as part of, like, you&#8217;re getting ready to go to a WordCamp, and you don&#8217;t know what I meant by open source or open source project or WordPress open source project, that&#8217;s fine.</p>\n\n\n\n<p>[00:07:08] <strong>Josepha:</strong> You&#8217;re going to learn all about it at the Contributor Day if you go, but the TLDR is that this software that you are about to choose to build your website on is built by thousands of people across the planet who are looking for the best solutions to problems that they have in their businesses that probably you will encounter or have encountered before. There&#8217;s no new problems under the sun, and open source methodologies kind of use the collective wisdom of everybody who has ever worked with a WordPress project or site and ran into a problem that they had to solve on their own, like this open source project, this community of people just make sure that that wisdom is collected and standardized and made available for all of eternity.</p>\n\n\n\n<p>That&#8217;s all you need to know. Low key. I&#8217;ve made Contributor Days sound so calming. However, that is a whole day thing. It happens before or after the WordCamp. It has separate registration so that organizers of your WordCamp can plan for how many folks need to be there to teach new and returning contributors, what to do. If I&#8217;m going to be honest, if you&#8217;re going to get overwhelmed at any WordPress event, it&#8217;s going to be one of these, but they are well worth the effort.</p>\n\n\n\n<p>[00:08:30] <strong>Josepha:</strong> Even if you just make a single contribution and never return, which I hope is not the case for you. I hope you do return. Even if you make a single contribution and never return, there&#8217;s something really grounding about seeing how much expertise and time, and care goes into this software that is, against all odds, completely free. So that&#8217;s all the tactical stuff, or a lot of it anyway.</p>\n\n\n\n<p>It at least gives you a sense for what you&#8217;re getting yourself into for your first-ever wonderful WordPress weekend. But I promised you some human stuff too. So here is my considerably shorter list of stuff to bring as a human being going to a WordCamp. There&#8217;s an optional one. I&#8217;ll start you off with an optional one. Come with an idea of what you think you want to learn. You don&#8217;t have to come with that if you don&#8217;t want to. Some of us don&#8217;t know what we don&#8217;t know yet, and that&#8217;s fine too. But if you have a sense for what you think you need to learn, you&#8217;ll have an easier time figuring out how to spend your time while you&#8217;re here.</p>\n\n\n\n<p>[00:09:30] <strong>Josepha:</strong> So, the non-optional things. Bring some way to exchange information. It can be QR codes, business cards, or pen and paper. It doesn&#8217;t really matter as long as it&#8217;s something that works for you to be sharing information with people that you meet. Because you never know when you&#8217;re going to meet your business soulmate, but the odds that you&#8217;re going to do it at a WordCamp are pretty dang high.</p>\n\n\n\n<p>The second thing to bring is bring what you need to be comfortable. Bring your water bottle, a change of shoes if you need it, spare battery for your phone, your glasses. This day is going to be long enough without worrying about small inconveniences. So bring what you need to make yourself comfortable.Â </p>\n\n\n\n<p>[00:10:09] <strong>Josepha:</strong> And finally bring your bravery. You will not know by looking at someone whether they&#8217;ve been doing WordPress stuff for two years or two weeks. But you can know that at some point, they were in the first two days of trying to figure this all out. One of the most endearing things about this community is the zeal they bring to solving a problem. So if you get lost or stuck, just ask the person next to you. We all remember what it was like to know nothing, and we are rooting for you to succeed. And that&#8217;s it. That&#8217;s your whole list. That&#8217;s everything you need to know to be the most prepared first-time attendee to a WordCamp ever. If that all sounded more overwhelming than just showing up, don&#8217;t worry.</p>\n\n\n\n<p>You can also just show up. That&#8217;s what I did. And even though I knew next to nothing, those WordCampers made me feel welcome and included and kept me coming back to learn more.</p>\n\n\n\n<p>[00:11:04] <strong>Josepha:</strong> Ah, WordCamps. Gosh, I love those things. So glad that we&#8217;re all getting back together for them.&nbsp;</p>\n\n\n\n<p>[00:11:10] (Music interlude)Â </p>\n\n\n\n<p>[00:11:18] <strong>Josepha:</strong> That brings us now, my friends, to our small list of big things. If you&#8217;re a first-time WordPresser, if you&#8217;ve never been to a WordCamp, and you don&#8217;t know what any of these things are, don&#8217;t worry; you can still go take a look at them, or you can wait until later when you&#8217;re less overwhelmed.</p>\n\n\n\n<p>Either way, but this is our small list of big things for middle of the year 2024. First thing on my list, the gender equality in WordPress businesses survey is still open. It aims to gain critical insight into the gender composition of leadership teams, the experiences of women and gender-diverse leaders and employees, and also take a look at the challenges and barriers to their career success. I care deeply about making sure that we have a way for folks who are traditionally and historically underrepresented in technology have a way to get into our space. Obviously, women and nonbinary folks are an area that I feel particularly called to help build those on-ramps for, but I have a great concern for that across the entire ecosystem and any intersection that we run into as we get more and more users into our space.Â </p>\n\n\n\n<p>[00:12:30] <strong>Josepha:</strong> If you are a woman, if you work with women, if you work in WordPress, if you work in a WordPress business, go take that survey, and let&#8217;s see what we find out about what it&#8217;s like to work in this space, as somebody that we normally don&#8217;t see.Â </p>\n\n\n\n<p>The second thing on our list is that WordCamp Asia 2025 dates and venue have been revealed. So WordCamp Asia 2023 and 2024 were both major successes, and we are excited to share that the dates and venue for next year will be February 20th, 21st, 22nd in 2025 in Manila, and you&#8217;ll be able to go over to that website, take a look at it, we&#8217;ll have a link in the show notes as always and maybe start planning your your next big Asian adventure.</p>\n\n\n\n<p>[00:13:13] <strong>Josepha:</strong> The third thing on my list is this new contributor wizard questionnaire. So, there are more than 20 teams to contribute to in the WordPress project. They all show up at those Contributor Days that I talked about. But there are more than 20 of them. They work on different parts of the WordPress project every day. And our passionate community offers contribution opportunities for everyone. I know, we know, that finding the right team is the key to a meaningful contributor experience. So, our interactive questionnaire is here to help you determine where to start. It is sometimes difficult to know whether you can contribute to a software if you are a designer, if you are a writer, if you are in marketing.</p>\n\n\n\n<p>And it turns out that you can contribute to WordPress with a bunch of skills that you otherwise would not have realized. So, we&#8217;ll have a link to the questionnaire in the show notes again. Also, it&#8217;s probably going to pop up on WordCamp sites, Contributor Day sites, anything that helps you all understand where you might find a little bit of success as a contributor is a good place for it to be. Take the questionnaire, see where you land, the WordPress sorting hat.Â </p>\n\n\n\n<p>[00:14:18] <strong>Josepha:</strong> And item number four. So we&#8217;ve made some updates, not we&#8217;ve made some updates, we have some updates from the Five for the Future program. So the Five for the Future program has a long history in the WordPress project. There are a couple of different episodes in this podcast where you can learn more about it.</p>\n\n\n\n<p>But, to bolster transparency and openness, we have an update on the current state of WordPress contributions as of the end of May 2024. In the past few months, we&#8217;ve made a lot of efforts to improve the program and contributor experience in WordPress. We&#8217;ve also done a little bit of work to kind of clean up the pledges that are in there for, people or companies or teams that have found that they couldn&#8217;t continue their contributions over time. That is fine too. But we&#8217;ll have a link to that update in the show notes as well.</p>\n\n\n\n<p>[00:15:09] <strong>Josepha:</strong> And that, my friends, is your small list of big things. Don&#8217;t forget to follow us on your favorite podcast app or subscribe directly on WordPress.org/news. You&#8217;ll get a friendly reminder whenever there&#8217;s a new episode. If you liked what you heard today, share it with a fellow WordPresser. Or, if you had questions about what you heard, you can share those with me at WPBriefing@WordPress.org. I am your host, Josepha Haden Chomposy. Thanks for tuning in today for the WordPress Briefing, and I&#8217;ll see you again in a couple of weeks.Â </p>\n\n\n\n<p>[00:15:36] (Music outro)Â </p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17352\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"WordPress 6.5.4 Maintenance Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://wordpress.org/news/2024/06/wordpress-6-5-4-maintenance-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 05 Jun 2024 15:57:15 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=17340\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:345:\"WordPress 6.5.4 is now available!This minor release features 5 bug fixes in Core. You can review a summary of the maintenance updates in this release by reading the Release Candidate announcement. WordPress 6.5.4 is a short-cycle release. The next major release will be version 6.6 planned for July 2024. If you have sites that support [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Aaron Jorbin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4663:\"\n<p><strong>WordPress 6.5.4 is now available!</strong><br>This minor release features <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;milestone=6.5.4&amp;group=status&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;col=keywords&amp;order=priority\">5 bug fixes in Core</a>. You can review a summary of the maintenance updates in this release by reading the <a href=\"https://make.wordpress.org/core/2024/05/30/wordpress-6-5-4-rc1-is-now-available/\">Release Candidate announcement</a>.</p>\n\n\n\n<p>WordPress 6.5.4 is a short-cycle release. The next major release will be <a href=\"https://make.wordpress.org/core/6-6/\">version 6.6</a> planned for July 2024.</p>\n\n\n\n<p>If you have sites that support automatic background updates, the update process will begin automatically.</p>\n\n\n\n<p>You can <a href=\"https://wordpress.org/wordpress-6.5.4.zip\">download WordPress 6.5.4 from WordPress.org</a>, or visit your WordPress Dashboard, click âUpdatesâ, and then click âUpdate Nowâ.</p>\n\n\n\n<p>For more information on this release, please <a href=\"https://wordpress.org/support/wordpress-version/version-6-5-4\">visit the HelpHub site</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Thank you to these WordPress contributors</h2>\n\n\n\n<p>This release was led by <a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a>, <a href=\"https://profiles.wordpress.org/costdev\">Colin Stewart</a>, and <a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>.</p>\n\n\n\n<p>WordPress 6.5.4 would not have been possible without the contributions of the following people. Their asynchronous coordination to deliver maintenance fixes into a stable release is a testament to the power and capability of the WordPress community.</p>\n\n\n\n<p class=\"is-style-wporg-props-medium\"><a href=\"//profiles.wordpress.org/jorbin&quot;\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/adrianduffell\">adrianduffell</a>, <a href=\"https://profiles.wordpress.org/azaozz\">Andrew Ozz</a>, <a href=\"https://profiles.wordpress.org/afragen\">Andy Fragen</a>, <a href=\"https://profiles.wordpress.org/beaulebens\">Beau Lebens</a>, <a href=\"https://profiles.wordpress.org/bernhard-reiter/\">Bernhard Reiter</a>, <a href=\"https://profiles.wordpress.org/ironprogrammer\">Brian Alexander</a>, <a href=\"https://profiles.wordpress.org/costdev\">Colin Stewart</a>, <a href=\"https://profiles.wordpress.org/nerrad\">Darren Ethier (nerrad)</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/lopo\">Enrico Battocchi</a>, <a href=\"https://profiles.wordpress.org/estelaris/\">Estela Rueda</a>, <a href=\"https://profiles.wordpress.org/johnjamesjacoby\">John James Jacoby</a>, <a href=\"https://profiles.wordpress.org/johnbillion\">John Blackbourn</a>, <a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/kevinwhoffman\">Kevin Hoffman</a>, <a href=\"https://profiles.wordpress.org/louiswol94\">Louis Wolmarans</a>, <a href=\"https://profiles.wordpress.org/hmbashar\">Md Abul Bashar</a>, <a href=\"https://profiles.wordpress.org/illuminea\">Miriam Schwab</a>, <a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>, <a href=\"https://profiles.wordpress.org/narenin\">Narendra Sishodiya</a>, <a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/pooja1210\">Pooja N Muchandikar</a>, <a href=\"https://profiles.wordpress.org/mikachan\">Sarah Norris</a>, <a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>, <a href=\"https://profiles.wordpress.org/smub\">Syed Balkhi</a>, <a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">How to contribute</h2>\n\n\n\n<p>To get involved in WordPress core development, head over to Trac, <a href=\"https://core.trac.wordpress.org/report/6\">pick a ticket</a>, and join the conversation in the <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> and <a href=\"https://wordpress.slack.com/archives/C06U06K50Q5\">#6-6-release-leads</a> channels. Need help? Check out the <a href=\"https://make.wordpress.org/core/handbook/\">Core Contributor Handbook</a>.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Props to @<a href=\"https://profiles.wordpress.org/afragen/\">afragen</a>, @<a href=\"https://profiles.wordpress.org/hellofromtonya/\">hellofromtonya</a> , and </em><a href=\"https://profiles.wordpress.org/angelasjin/\">@<em>angelasjin</em></a><em> for proofreading.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17340\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:66:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.6 Beta 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://wordpress.org/news/2024/06/wordpress-6-6-beta-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 04 Jun 2024 17:44:29 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"beta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:8:\"releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=17289\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:351:\"WordPress 6.6 Beta 1 is here! Please download and test it. This beta version of the WordPress software is under development. Please do not install, run, or test this version of WordPress on production or mission-critical websitesâyou risk unexpected results if you do. Instead, install Beta 1 on local sites and testing environments in any [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"marybaum\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:16244:\"\n<p>WordPress 6.6 Beta 1 is here! Please download and test it.</p>\n\n\n\n<p><strong>This beta version of the WordPress software is under development. </strong>Please do not install, run, or test this version of WordPress on production or mission-critical websitesâyou risk unexpected results if you do.</p>\n\n\n\n<p>Instead, install Beta 1 on local sites and testing environments in any of these four ways:</p>\n\n\n\n<figure class=\"wp-block-table\"><table><tbody><tr><th>Plugin</th><td>Install and activate the <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> plugin on a WordPress install. (Select the âBleeding edgeâ channel and âBeta/RC Onlyâ stream).</td></tr><tr><th>Direct Download</th><td>Download the <a href=\"https://wordpress.org/wordpress-6.6-beta1.zip\">Beta 1 version (zip)</a> and install it on a WordPress website.</td></tr><tr><th>Command Line</th><td>Use this <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> command:<br><code>wp core update --version=6.6-beta1</code></td></tr><tr><th>WordPress Playground</th><td>Use a <a href=\"https://playground.wordpress.net/#{%20%22preferredVersions%22:%20{%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20},%20%22features%22:%20{%20%22networking%22:%20true%20},%20%22steps%22:%20[%20{%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20}%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20},%20%22options%22:%20{%20%22activate%22:%20false%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20}%20]%20}\" data-type=\"link\" data-id=\"https://playground.wordpress.net/#{%20%22preferredVersions%22:%20{%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20},%20%22features%22:%20{%20%22networking%22:%20true%20},%20%22steps%22:%20[%20{%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20}%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20},%20%22options%22:%20{%20%22activate%22:%20false%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20}%20]%20}\">6.6 Beta 1 WordPress Playground instance</a> to test the software directly in your browser. This might be the easiest way everâno separate sites, no setup. Just click and go!&nbsp;</td></tr></tbody></table></figure>\n\n\n\n<p>The scheduled final release date for WordPress 6.6 is <strong>July 16, 2024</strong>. Your help testing Beta and RC versions over the next six weeks is vital to making sure the final release is everything it should be: stable, powerful, and intuitive.</p>\n\n\n\n<h2 class=\"wp-block-heading\">How important is your testing? </h2>\n\n\n\n<p><strong>Features in this Beta release may be changed or removed between now and the final release.</strong> Early attention from testers like you is critical to finding and reporting potential bugs, usability issues, or compatibility problems to make sure developers can address them before the final release. You don&#8217;t need any contribution experience, and this is a fantastic way to begin your WordPress contributor story!</p>\n\n\n\n<h2 class=\"wp-block-heading\">If you find an issue</h2>\n\n\n\n<p>If you run into an issue, please share it in the <a href=\"https://wordpress.org/support/forum/alphabeta/\">Alpha/Beta area</a> of the support forums. If you are comfortable submitting a reproducible bug report, you can do so <a href=\"https://core.trac.wordpress.org/newticket\">via WordPress Trac</a>. You can also check your issue against a list of <a href=\"https://core.trac.wordpress.org/tickets/major\">known bugs</a>.</p>\n\n\n\n<p>Want to know more about testing in general, and how to get started? Follow the <a href=\"https://make.wordpress.org/test/\">testing initiatives in Make Core</a> and join the <a href=\"https://wordpress.slack.com/messages/core-test/\">#core-test channel</a> on <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<p>Like every version since 5.0 in 2018, WordPress 6.6 will integrate a host of new features from the last several releases of the Gutenberg plugin. Learn more about Gutenberg updates since WordPress 6.5 in the <a href=\"https://make.wordpress.org/core/tag/gutenberg-new/\">Whatâs New in Gutenberg</a> posts for versions <a href=\"https://make.wordpress.org/core/2024/02/28/whats-new-in-gutenberg-17-8-28-february/\">17.8</a>, <a href=\"https://make.wordpress.org/core/2024/03/13/whats-new-in-gutenberg-17-9-13-march/\">17.9</a>, <a href=\"https://make.wordpress.org/core/2024/03/27/whats-new-in-gutenberg-18-0-27-march/\">18.0</a>, <a href=\"https://make.wordpress.org/core/2024/04/10/whats-new-in-gutenberg-18-1-10-april/\">18.1</a>, <a href=\"https://make.wordpress.org/core/2024/04/24/whats-new-in-gutenberg-18-2-24-april/\">18.2</a>, <a href=\"https://make.wordpress.org/core/2024/05/08/whats-new-in-gutenberg-18-3-8-may/\">18.3</a>, and <a href=\"https://make.wordpress.org/core/2024/05/23/whats-new-in-gutenberg-18-4-22-may/\">18.4</a>. The final version will also include Gutenberg 18.5; the Beta 2 post will link to that.</p>\n\n\n\n<p class=\"is-style-default\">WordPress 6.6 Beta 1 contains 97 enhancements and 101 fixes for the editor, in a total of about 206 <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;milestone=6.6&amp;group=component&amp;max=500&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;order=priority\">tickets for WordPress 6.6 Core</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">The vulnerability bounty doubles in the beta period</h2>\n\n\n\n<p>The WordPress community sponsors a <a href=\"https://make.wordpress.org/security/2024/06/04/wordpress-6-6-is-coming/\">monetary reward for reporting new, unreleased security vulnerabilities.</a> That reward doubles during the period between Beta 1 on June 4 and the final Release Candidate (RC) that will happen June 25. Please follow the project&#8217;s responsible-disclosure practices detailed on this <a href=\"https://hackerone.com/wordpress\">HackerOne page</a> and in this <a href=\"https://wordpress.org/about/security/\">security white paper</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Whatâs coming to WordPress 6.6?</h2>\n\n\n\n<p>This yearâs second major release is about polish and finesse. Features that landed in the last few releases have new flexibility and smoother flowsâand a few new tricks. And of course there are a few brand-new features.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Data Views updates</h3>\n\n\n\n<p>Part of the groundwork for phase 3, Data Views get new and improved experience of working with information in the Site Editor. A new layout consolidates patterns and template parts, gets you to general management views in fewer clicks, and packs in a wide range of refinements.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Overrides in synced patterns</h3>\n\n\n\n<p>What if you could keep a synced patternâs <em>look and feel</em> everywhere it appearsâkeeping it on brandâbut have different <em>content</em> everywhere it appears?</p>\n\n\n\n<p>For instance, maybe youâre building a pattern for recipes. Ideally, you want to keep the overall design of the recipe card consistent on every post that will have a recipe. But the recipe itselfâthe ingredients, the steps, special notes on techniqueâwill be different every time.</p>\n\n\n\n<p>And perhaps, in the future, other people might need to change the design of the recipe pattern. It would be nice to know they can do that, and that the content in existing recipes will stay right where it is.</p>\n\n\n\n<p>In version 6.6, you can make all that happen, and overrides in synced patterns are the way you do it.</p>\n\n\n\n<h3 class=\"wp-block-heading\">See all the blocks</h3>\n\n\n\n<p>Up to now, when you had a block selected and then opened the block Inserter, you only saw the blocks you were allowed to add to your selected block. Where were all the others?</p>\n\n\n\n<p>In 6.6, when you have a block selected, you get two lists. First, there&#8217;s the list of blocks you can insert at your selected block. Then you get a list with all the other blocks. So you can get an idea of what you can use in your selected block, and what other blocks you could use in another area. In fact, if you select a block from that second list, WordPress 6.6 will add it below your block, to use in whatever you build next.</p>\n\n\n\n<h3 class=\"wp-block-heading\">A new publish flow</h3>\n\n\n\n<p>Version 6.6 brings the post and site editors closer together than ever. So whether youâre writing for a post in the post editor or a page in the Site Editor, your experience will be about the same.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Style variations</h3>\n\n\n\n<p>If a block theme comes with style variations, 6.6 vastly expands your design options right out of the box, without installing or configuring a single thing. Because in 6.6, your theme  pulls the color palettes and typography style sets out of its installed variations to let you mix and match for a whole world of expanded creative expression.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Section styles </h3>\n\n\n\n<p>Do you build themes? Now you can define style options for separate sections of multiple blocks, including inner blocks.</p>\n\n\n\n<p>Then your users can apply those block style variations to entire groups of blocks, effectively creating branded sections they can curate across a site.</p>\n\n\n\n<h4 class=\"wp-block-heading\">A note about CSS specificity</h4>\n\n\n\n<p>To make it easier for your variations to override the global styles CSS, those styles now come wrapped in `:root`. That limits their specificity. <a href=\"https://github.com/WordPress/gutenberg/discussions/61810\">For details, read the full discussion on GitHub.</a></p>\n\n\n\n<h3 class=\"wp-block-heading\">A native Grid layout</h3>\n\n\n\n<p>Grid is a new variation for the Group block that lets you arrange the blocks inside it as a grid. If you&#8217;ve been using a plugin for this, now you can make your grids natively.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Better pattern management in Classic themes</h3>\n\n\n\n<p>You heard right: You can do everything with patterns in Classic themes that you can in a block theme. You can see all the patterns available to you in a single view and insert a pattern on the fly. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Negative. Margins.</h3>\n\n\n\n<p>They&#8217;re here: negative margin values, so you can make objects overlap in your design. As a guardrail, you can only set a negative margin by typing an actual negative number, not by using the slider. Thatâs to keep people from adding negative values they didn&#8217;t intend.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Rollback auto-updates</h3>\n\n\n\n<p>Now you can have the convenience of setting all your plugins to auto-update and the inner peace you get from knowing that if anything goes wrong, 6.6 will do a rollback. Automatically.</p>\n\n\n\n<p><strong><em>This post <strong><em>reflects the latest changes</em></strong> as of June 4, 2024.</em></strong> </p>\n\n\n\n<p><strong>Again, the features in this first beta may change, based on what testers like you find.</strong></p>\n\n\n\n<p>Get an overview of the <a href=\"https://make.wordpress.org/core/6-6/\">6.6 release cycle</a>, and check the <a href=\"https://make.wordpress.org/core/\">Make WordPress Core blog</a> for <a href=\"https://make.wordpress.org/core/tag/6-6/\">6.6-related posts</a> in the next few weeks for further details.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Just for you: a Beta 1 haiku</h3>\n\n\n\n<p>Negative margins<br>Embellish all the new ways<br>To design and build  </p>\n\n\n\n<p class=\"has-text-align-left is-style-default\"><em>Thanks very much to <a href=\'https://profiles.wordpress.org/meher/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>meher</a>, <a href=\'https://profiles.wordpress.org/audrasjb/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>audrasjb</a>, <a href=\'https://profiles.wordpress.org/fabiankaegy/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>fabiankaegy</a>, <a href=\'https://profiles.wordpress.org/colorful-tones/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>colorful-tones</a>, </em><a href=\'https://profiles.wordpress.org/davidbaumwald/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>davidbaumwald</a>,<em> <a href=\'https://profiles.wordpress.org/dansoschin/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>dansoschin</a>, <a href=\'https://profiles.wordpress.org/desrosj/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>desrosj</a>, <a href=\'https://profiles.wordpress.org/atachibana/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>atachibana</a>, <a href=\'https://profiles.wordpress.org/ehtis/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>ehtis</a>, <a href=\'https://profiles.wordpress.org/adamsilverstein/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>adamsilverstein</a>, <a href=\'https://profiles.wordpress.org/joedolson/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>joedolson</a>, and <a href=\'https://profiles.wordpress.org/webcommsat/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>webcommsat</a> for reviewing and collaborating on this post!</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17289\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"WordCamp Europe 2024: Mid-Year Update and Q&amp;A with Matt Mullenweg\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:99:\"https://wordpress.org/news/2024/05/wordcamp-europe-2024-mid-year-update-and-qa-with-matt-mullenweg/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 31 May 2024 16:45:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:6:\"Events\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"WCEU\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=17286\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:217:\"WordCamp Europe 2024 kicks off on June 13, gathering WordPressers from across the globe to Torino, Italy.Â Find out more about the conference and how to live stream project Cofounder Matt Mullenweg\'s mid-year update. \";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Lauren Stein\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2144:\"\n<p>WordCamp Europe 2024 kicks off on June 13, gathering WordPressers from across the globe to Torino, Italy.Â </p>\n\n\n\n<p>The highly anticipated conference has a packed schedule starting with <a href=\"https://europe.wordcamp.org/2024/contributor-day/\">Contributor Day</a> and will feature a notable roster of speakers. Other highlights will include <a href=\"https://europe.wordcamp.org/2024/workshops/\">engaging workshops</a> covering a variety of disciplines (including one for youth and teens) and <a href=\"https://europe.wordcamp.org/2024/wordcamp-connect/\">WordCamp Connect</a>, a dedicated space for attendees to meet and network with additional community-led sessions.</p>\n\n\n\n<p>The conference will conclude with an exciting mid-year project update from WordPress Cofounder Matt Mullenweg, including a live Q&amp;A session. You can watch Mattâs presentation on June 15, 2024, streaming live on the <a href=\"https://youtube.com/wordpress\">WordPress YouTube channel</a> starting at 4:30 p.m. Central European Summer Time (2:30 p.m. UTC).</p>\n\n\n\n<p><strong>What:</strong> <a href=\"https://europe.wordcamp.org/2024/session/wordpress-project-summer-update/\" data-type=\"link\" data-id=\"https://europe.wordcamp.org/2024/session/wordpress-project-summer-update/\">WordPress Project Summer Update</a> + Q&amp;A Session with Matt Mullenweg<br><strong>When: </strong>June 15, 2024 at 2:30 p.m. UTC (Start of live stream)<br><strong>Where: </strong><a href=\"https://europe.wordcamp.org/2024/venue/\">Lingotto Conference and Exhibition Centre<strong><br></strong></a><strong>Streaming: </strong><a href=\"https://youtube.com/wordpress\">Watch the live stream</a> on the WordPress YouTube channel.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Have a question for Matt?</h2>\n\n\n\n<p>If youâre unable to attend WordCamp Europe 2024 in person, youâre welcome to <a href=\"mailto:ask-matt@wordcamp.org\">email your questions</a> instead. Given the number of questions expected both in-person and online, only some of the submitted questions may be answered live.Â </p>\n\n\n\n<p>Whether youâre touching down in Torino or streaming from elsewhere, see you very soon!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17286\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:61:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"WP Briefing: Episode 80: Unlocking Your WordPress Potential with Learn WordPress Tools\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:108:\"https://wordpress.org/news/2024/05/episode-80-unlocking-your-wordpress-potential-with-learn-wordpress-tools/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 27 May 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"wp-briefing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=17278\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:493:\"Welcome to another episode of the WordPress Briefing! In this episode, your host, Josepha Haden Chomphosy, delves into the incredible resources available to help you broaden your WordPress expertise. Whether you\'re just starting out or looking to deepen your skillset, these tools and tutorials offer something for everyone. Join us as we explore how Learn WordPress can be your guide on the journey to mastering WordPress, providing invaluable support and community connections along the way.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:60:\"https://wordpress.org/news/files/2024/05/WPB80-2Enhanced.mp3\";s:6:\"length\";s:1:\"0\";s:4:\"type\";s:0:\"\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:14785:\"\n<p>Welcome to another episode of the WordPress Briefing! In this episode, your host, Josepha Haden Chomphosy, delves into the incredible resources available to help you broaden your WordPress expertise. Whether you&#8217;re just starting out or looking to deepen your skillset, these tools and tutorials offer something for everyone. Join us as we explore how Learn WordPress can be your guide on the journey to mastering WordPress, providing invaluable support and community connections along the way.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Host:&nbsp;<a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a><br>Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br>Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br>Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a><br>Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://events.wordpress.org/\">WordPress Events </a></li>\n\n\n\n<li><a href=\"https://learn.wordpress.org/\">Learn WordPress</a>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://learn.wordpress.org/online-workshops/\">Online Workshops</a></li>\n\n\n\n<li><a href=\"https://learn.wordpress.org/tutorials/\">Tutorials</a></li>\n\n\n\n<li><a href=\"https://learn.wordpress.org/lesson-plans/\">Lesson Plans</a></li>\n</ul>\n</li>\n\n\n\n<li><strong>Small List of Big Things</strong>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://europe.wordcamp.org/2024/youth-teens-workshop-at-wordcamp-europe-2024/\" target=\"_blank\" rel=\"noreferrer noopener\">WordCamp Europe Youth &amp; Teen Workshop Registration is Open</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/05/03/roadmap-to-6-6/\" target=\"_blank\" rel=\"noreferrer noopener\">Roadmap to WordPress 6.6</a></li>\n\n\n\n<li><a href=\"https://us.wordcamp.org/2024/introducing-showcase-day/\" target=\"_blank\" rel=\"noreferrer noopener\">WordCamp US 2024 Showcase Day</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/2024/04/08/share-your-feedback-with-meetup-com/\">Share Feedback with&nbsp;Meetup.com</a></li>\n</ul>\n</li>\n\n\n\n<li>Have a question you&#8217;d like answered? Submit them to&nbsp;<a href=\"mailto:wpbriefing@WordPress.org\">WPBriefing@WordPress.org</a>.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcript</h2>\n\n\n\n<span id=\"more-17278\"></span>\n\n\n\n<p>[00:00:10] <strong>Josepha:</strong> Hello, everyone, and welcome to the WordPress Briefing, the podcast where you can catch quick explanations of the ideas behind the WordPress open source project, some insight into the community that supports it, and get a small list of big things coming up in the next two weeks. I&#8217;m your host, Josepha Haden Chomphosy.</p>\n\n\n\n<p>Here we go!</p>\n\n\n\n<p>[00:00:28] (Intro Music)&nbsp;</p>\n\n\n\n<p>[00:00:40] <strong>Josepha:</strong> My friends, I don&#8217;t know about where you live, but where I live, it&#8217;s graduation season. Students all across the region are either gearing down for a little bit of a brain break or gearing up for the next big adventure in their lives. And as I watch these students discover the next phases in their lives, whether it looks good or bad, whether it feels fearful or faithful, I can&#8217;t help but think back to my last big change.</p>\n\n\n\n<p>[00:01:07] <strong>Josepha:</strong> The one that brought me here to WordPress. I was working in insurance at the time and investing in a side hustle. And as is often the case with side hustles, discovered that knowing something about marketing myself was going to be key. Now, this next bit, I know that a lot of you will understand immediately. After that realization, I entered a period in my life where I was learning how to invest in my hoped-for side hustle so that I could realize my hoped-for dreams while also having to succeed at the job that I was using to pay my bills.</p>\n\n\n\n<p>By some singular coincidence, I wound up being introduced to the WordPress project, where I found not only the tools it turned out I needed but also people who were willing to help me learn them. For me, during that time, the cost to get access to both the tool and that support was basically zero. Like the whole cost to me was get those WordPress people together in a room to talk about WordPress for an hour.</p>\n\n\n\n<p>[00:02:04] <strong>Josepha:</strong> And that&#8217;s something that I always want to do anyway. I always want to get people together. And if what we&#8217;re talking about is WordPress, and that is what I need to learn about, then so be it. I realize that there is a little bit of privilege in that story and a whole lot of persistence. It&#8217;s not like I discovered it, and overnight, everything worked out well, and perfectly, and correctly.</p>\n\n\n\n<p>However, all of the struggles to get what I got accomplished done aside. One of the things that I love the most about how the WordPress project has evolved over time is that we took that already low-cost, low-barrier concept and did everything in our power to take that low-cost, low-barrier and make it available to as many people as possible in as many points in their journey as possible.</p>\n\n\n\n<p>So, if you&#8217;re at the start of your career or thinking about a bit of a career change, I have some resources for you. Like, stick around. But before we get to the resources, I want to make sure that you hear this. Learning WordPress things, whether that&#8217;s the software itself, or how to run a business supported by WordPress, or how to support other businesses by building them WordPress stuff, learning these skills now is an investment in who you want to be.</p>\n\n\n\n<p>[00:03:20] <strong>Josepha:</strong> It&#8217;s placing a bet that&#8217;s grounded in what you think you can bring to the world before anyone else might have figured out it&#8217;s what they need in their lives. And when you do that, in WordPress, you&#8217;re accessing and hopefully one day contributing to an equitable framework that doesn&#8217;t require you to understand it in order for you to benefit from it.</p>\n\n\n\n<p>You can do hard things, and hopefully, these resources make those hard things a little easier. I&#8217;m going to take us through a whirlwind wayfinding list. I&#8217;ll generally be focused on time required and then kind of like necessary actions or context that would be useful for you to know. But remember that your mileage may vary.</p>\n\n\n\n<p>[00:04:01] <strong>Josepha:</strong> If something sounds close but not perfect, I encourage you to give it a try anyway. The worst that happens is you try something different next time. Or, in the best-case scenario, you create something that other folks also have been missing. There was something that was close for them but not perfect either, and maybe you found the thing that&#8217;s perfect for them.</p>\n\n\n\n<p>So, here is my whirlwind wayfinding list. Let&#8217;s go. Only have one hour a week and prefer a little company in your learning? Check out a meetup event near you. You can find those listed in your dashboard or on events.WordPress.org, but frequently, they happen during the week, after work hours, sometimes they happen on the weekend, they happen like in libraries or coffee shops.</p>\n\n\n\n<p>So, there are a lot of different ways that these events come together, and surely, there will be something that is the sort of low-key event that you want. But if not, you can always reach out to your local chapter and see how you can get involved with that, how you can help them create a new meetup event.</p>\n\n\n\n<p>[00:05:02] <strong>Josepha:</strong> The next option, if you only have an hour a week, but you actually don&#8217;t want company but still use some external support, I would check out one of our online workshops. There are cohorts for each workshop, and they&#8217;re run by facilitators so that you can learn and socialize from the comfort and safety of your own space, or if you really are super strapped for time, that can help with like not having to commute anywhere. Next up on our list, feel like you could average an hour a week, but honestly, would prefer it to be in one big chunk? Check out a WordCamp near you.</p>\n\n\n\n<p>Those are a little bit like the meetups but quite a bit bigger and a lot more content, a lot more learning available, and gets you into a different kind of group of people in your local area. Those happen about once a year per city or region, but if there&#8217;s not one within a comfortable traveling distance for you, it might be a good chance for you to do a mini business trip, or if you&#8217;re doing it as current career development, see if your boss, or your boss self, if you are your own boss, has a continuing education budget available for you.</p>\n\n\n\n<p>[00:06:08] <strong>Josepha:</strong> Have 30 minutes or so a week and don&#8217;t need any external motivation? On the one hand, I am a little jealous. I sometimes need my own external motivation. But, if that&#8217;s not you, if you can just self-drive forever, then courses over on learn.WordPress.org are just about your speed. We even have a series of learning pathways in development that curate all the courses you need to achieve particular milestones.</p>\n\n\n\n<p>You can also help to create those. If you have been all the way through your learning journey and you&#8217;re, like, the most WordPressy WordPresser we&#8217;ve ever seen, and you just want to make sure that other people have the same opportunities you&#8217;ve had, that&#8217;s an excellent opportunity to show up and make sure that the knowledge is still available, still free, still can be accessed.</p>\n\n\n\n<p>And finally, if you have unpredictable time and also still comfortable being completely self-driven, We have in the WordPress ecosystem countless videos, blogs, tutorials, and a ton of content creators that are behind them that specialize in teaching WordPress basics but also leveling up existing knowledge. And if your type of existing knowledge is in the, like, gathering the network to succeed, sort of area. We even have podcasts and blogs that are dedicated to the more businessy side of WordPress, how to make this function in the WordPress ecosystem.</p>\n\n\n\n<p>[00:07:32] <strong>Josepha:</strong> As always, I&#8217;ll have links for everything in the show notesâjust myriad links because this isn&#8217;t even all that we need to share with you today. And I&#8217;m going to say this last thing one more time because I really, really mean it like a whole, whole lot. I know it&#8217;s hard, bordering on impossible sometimes, to carve out time to learn new things. But when you&#8217;re ready to invest in yourself, I&#8217;m pretty sure that these resources will be here to support your hoped-for dreams.</p>\n\n\n\n<p>[00:07:58] (Music interlude)&nbsp;</p>\n\n\n\n<p>[00:08:05] <strong>Josepha:</strong> And that brings us now to our small list of big things. First up is speaking of learning, speaking of investing in your future. WordCamp Europe has a youth and teen workshop going on. The registration for that is still open. It is open for students aged 10 to 16. It&#8217;s gonna be a hands-on workshop. They&#8217;ll get to build their own website with WordPress and then explore some cutting-edge technology from VR to AI and learn essential internet safety skills. We&#8217;re going to be running that on June 13th. It will be in both English and Italian. I will leave a link to the registration in the show notes.</p>\n\n\n\n<p>And the next thing on our list is pretty much related. It&#8217;s kind of related. At WordCamp US this year, we have a Showcase Day. Now, this is new to WordCamp US, and it&#8217;s all about pushing the boundaries of what WordPress can do. It will feature presentations, demos, and technical workshops for all kinds of projects, from high-profile, large-scale builds with innovative integrations to more niche creative implementations that still have a big impact. Submissions are now open for it. If you are working on something that is really cool and uses WordPress and want to show it off to the WordPress community, wander over there, submit your project; let&#8217;s take a look at it and see if we can get it into that showcase lineup, but if you are looking for inspiration about what WordPress can do, if you&#8217;re still figuring out how this can work the best for you, that&#8217;s going to be a great opportunity to look at some unusual implementations so that you can get an idea for how big this thing can get.</p>\n\n\n\n<p>[00:09:43] <strong>Josepha:</strong> And just some tactical things. The next two things on my small of big things are two tactical items. One is that WordPress 6.6 is on the move; as always, we have Beta 1 scheduled pretty soon here. So, dig into our priority features. I will leave a link to the roadmap for WordPress 6.6. We&#8217;re targeting, if I recall correctly, middle of July for that release. And so it&#8217;s coming up faster than you think. And we would absolutely love for you to come in, test the Beta, tell us what&#8217;s broken so that we can fix it before it gets out. We can&#8217;t fix the things if you don&#8217;t tell us they&#8217;re broken.Â </p>\n\n\n\n<p>[00:10:17] <strong>Josepha:</strong> And then the final thing on our small list of big things is that speaking of not being able to fix things that we don&#8217;t know are broken. So, we use meetup.com to manage all of our meetup series. Well, most of our meetup series anyway, but they are planning to invest in some product improvements, and they have asked for feedback from the WordPress community. Historically, we are one of the largest, most active communities on their platform. And so, if you could fill out the feedback form, if you&#8217;ve been to a meetup, or if you tried to find a meetup using meetup.com and did not succeed, that&#8217;s probably also relevant information. I&#8217;ll have a link to that here as well. It will go directly to their product team. And hopefully we&#8217;ll see some product improvements for the WordPress community in the future.</p>\n\n\n\n<p>[00:11:01] <strong>Josepha:</strong> And that, my friends, is your small list of big things. Don&#8217;t forget to follow us, follow me on your favorite podcast app, or subscribe directly on WordPress.org/news. You&#8217;ll get a friendly reminder whenever there&#8217;s a new episode, and if you liked what you heard today, share it with a fellow WordPresser. Or, if you had questions about what you heard, you can share those with me at WPBriefing@WordPress.org. I&#8217;m your host, Josepha Haden Chomphosy. Thanks again, and I&#8217;ll see you in a couple of weeks.&nbsp;</p>\n\n\n\n<p>[00:11:29] (Music outro)&nbsp;</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17278\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:61:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"WP Briefing: Episode 79: Why Start a WordPress Media Corps (and Why Now?)\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://wordpress.org/news/2024/05/episode-79-why-start-a-wordpress-media-corps-and-why-now/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 14 May 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"wp-briefing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=17253\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:470:\"Thereâs a new initiative in the WordPress community: the WordPress Media Corps. In todayâs episode of the WordPress Briefing, youâll find out how it came to be, first as a nugget of an idea during the pandemic and now as an active experiment. Learn how this shift in focus values the ongoing impact, and often invisible effort, of independent WordPress mediaâand seeks to help them more easily deliver engaging, high-quality WordPress content to their audiences.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:51:\"https://wordpress.org/news/files/2024/05/WPB079.mp3\";s:6:\"length\";s:1:\"0\";s:4:\"type\";s:0:\"\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:12000:\"\n<p>Thereâs a new initiative in the WordPress community: the WordPress Media Corps. In todayâs episode of the WordPress Briefing, youâll find out how it came to be, first as a nugget of an idea during the pandemic and now as an active experiment. Learn how this shift in focus values the ongoing impact, and often invisible effort, of independent WordPress mediaâand seeks to help them more easily deliver engaging, high-quality WordPress content to their audiences.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Host:&nbsp;<a href=\"https://profiles.wordpress.org/chanthaboune/\">Josepha Haden Chomphosy</a><br>Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br>Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br>Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a><br>Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/marketing/2024/03/20/making-a-wordpress-media-corps/\">Making a WordPress Media Corps</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/marketing/2024/04/29/wordpress-media-corps-next-steps/\">WordPress Media Corps Next Steps</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/media-corps/2024/05/03/wordpress-media-corps-initial-roadmap/\">WordPress Media Corps Initial Roadmap</a></li>\n\n\n\n<li><a href=\"https://wordpress.slack.com/archives/C0723V9S7CY\">#media-corps</a>&nbsp;Slack channel</li>\n\n\n\n<li><strong>Small List of Big Things</strong>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2024/04/23/wordpress-6-6-call-for-volunteers-update/\" target=\"_blank\" rel=\"noreferrer noopener\">WordPress 6.6 call for volunteers update</a></li>\n\n\n\n<li><a href=\"https://wordpress.org/news/2024/05/wordpress-6-5-3-maintenance-release/\" target=\"_blank\" rel=\"noreferrer noopener\">WordPress 6.5.3 maintenance release</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/openverse/2024/04/16/introducing-collection-views-for-tags-creators-and-sources/\" target=\"_blank\" rel=\"noreferrer noopener\">Openverse Introduces Collection views for Tags, Creators, and Sources</a></li>\n\n\n\n<li><a href=\"https://europe.wordcamp.org/2024/schedule/\" target=\"_blank\" rel=\"noreferrer noopener\">WordCamp Europe 2024 Schedule Released</a></li>\n</ul>\n</li>\n\n\n\n<li>Have a question you&#8217;d like answered? Submit them to&nbsp;<a href=\"mailto:wpbriefing@WordPress.org\">WPBriefing@WordPress.org</a>.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcript</h2>\n\n\n\n<span id=\"more-17253\"></span>\n\n\n\n<p>[00:00:00]&nbsp;<strong>Josepha:</strong>&nbsp;Hello, everyone, and welcome to the WordPress Briefing, the podcast where you can catch quick explanations of the ideas behind the WordPress open source project, some insight into the community that supports it, and get a small list of big things coming up in the next two weeks.</p>\n\n\n\n<p>I&#8217;m your host, Josepha Haden Chomphosy. Here we go!&nbsp;</p>\n\n\n\n<p>[00:00:28] (Intro Music)&nbsp;</p>\n\n\n\n<p>[00:00:39] <strong>Josepha:</strong> If you&#8217;ve been keeping an eye on the WordPress marketing space for the past few months, today&#8217;s topic will be no surprise to you. Today, we&#8217;re talking about the WordPress Media Corps. It&#8217;s a bit of a controversial topic; there&#8217;s no point denying that, so today, I want to take a little journey through its history.</p>\n\n\n\n<p>The WordPress Media Corps is an idea that goes back probably four, maybe five years ago. I don&#8217;t know what year it isâfour years, five, four, or five years ago. It was the height of our COVID isolation. So I was spending a lot of time with our WordPress media folks, people who hosted podcasts, who gathered weekly roundups, and who were writing these nuanced and thoughtful newsletters.</p>\n\n\n\n<p>[00:01:19] <strong>Josepha:</strong> And during the prep phases for these, I was witnessing all the work that goes into them, researching questions and topics, marketing both before and after any appearance, and consistently engaging with the audiences they had grown over time. Over the course of the year, I wound up in two or three different conversations with these hosts about how this does or doesn&#8217;t fit in the WordPress project as a way to contribute.</p>\n\n\n\n<p>Now, invisible contributions are a persistent concern for any open source project and is one of the problems I am often most desperate to solve. As with so many long-standing problems, if the solution were easy, it wouldn&#8217;t still be a problem. And that&#8217;s the case here as well. I&#8217;ve got a quick side note on why this is a hard problem to solve at the end of the episode. It&#8217;s relevant to the overall discussion, but not if you&#8217;re only here to learn about how we arrived at the Media Corps. So, choose your own adventure!&nbsp;</p>\n\n\n\n<p>[00:02:16] <strong>Josepha:</strong> So, during one of those discussions, Allie Nimmons reminded me that we have always relied on third-party supporters to share information about WordPress. It was a smaller group than we have now, much less variety in the format, but they didn&#8217;t have contribution acknowledgments either, right?&nbsp;</p>\n\n\n\n<p>And she was right. They were included in something called the WP Planet. And I remember that I said to her what I wouldn&#8217;t give to be able to acknowledge the value that WordPress media folks bring to our ecosystem. These folks who have more flexibility than us can be a little more, more nimble who are canonical power users of WordPress, sharing not only what they are excited about now and in the near future but also the things that they had to learn in order to get the most out of the features and the software.</p>\n\n\n\n<p>[00:03:07] <strong>Josepha:</strong> Like that&#8217;s practically a gold standard of the people that we want to have talking about us.&nbsp; And, for folks who&#8217;ve worked with Allie, you probably can predict what&#8217;s next. You know she&#8217;s not afraid to call it like she sees it, and she called me on my excessive dreaming. She asked me what actually was stopping me from getting that done. I don&#8217;t recall if I had an answer for her at the time. I, I probably didn&#8217;t, but ultimately, I think the answer was, most likely, that I was afraid to try. </p>\n\n\n\n<p>So you might be asking yourself, what has changed my mind since then? What has changed since 2020, when I was maybe too scared to get this done? Why does now feel like the right time compared to when I was first thinking through it? Well, for starters, when we look at then, we look at the context of then; it was my second year leading us. It was 2020, the year of COVID. And I was desperately trying to roll out a disaster recovery plan, incomplete though it was.</p>\n\n\n\n<p>[00:04:06] <strong>Josepha:</strong> I wasn&#8217;t sure how much more disruption we as a community could stand, so I didn&#8217;t want to take any more risks than I had to. Which brings us to today. One of my big obstacles to tackle this year is our plateauing growth. I said it right there in my big-picture post for 2024. Re-engaging those gold standard users who are talking about us while making it clear that their contributions add to the success of the project seems like a high-impact opportunity to me.</p>\n\n\n\n<p>We&#8217;ve kicked off our initial experiment for the Media Corps. As with many high-impact projects, there&#8217;s also a high potential for risk, so I&#8217;m trying to get a clear indication of success as early as possible. Because of that, the experiment is time-limited and has pretty strict guidelines up front. It&#8217;s also being paired with a pause on the current work with the marketing team, just so that we can focus as much attention to get that signal sooner rather than later.</p>\n\n\n\n<p>[00:05:01] <strong>Josepha:</strong> Not everyone agrees with this plan, which is to be expected. There are so many seasoned marketing professionals in WordPress, myself included, and I mean, our software is a primary tool in so many marketing tool belts. It probably would be odd if we didn&#8217;t have any marketers around. So there you have it, a brief explanation of how we got to today&#8217;s Media Corps experiment.&nbsp;</p>\n\n\n\n<p>Quick side note on why it&#8217;s a hard problem is that a good first step to acknowledging invisible work is removing the need for human recognition of the work. I&#8217;ve worked with teams, guided them since I got here to define contributions as granularly as possible so that we can find ways to attach automated triggers to them so that you don&#8217;t have to do a ton of invisible things for someone to notice them and give you props for them. Obviously, the more automation, the more dehumanization, and of course, the work of breaking things into tiny chunks feels like micromanagement; it feels like value assessment.</p>\n\n\n\n<p>[00:06:01] <strong>Josepha:</strong> It also often felt like kind of a toxic tallying of who was doing what where. None of that is what any of us wanted when I started that work, and it&#8217;s certainly not what I want now. But because it is so often misread as a way to, like, separate out good contributions from bad, not all teams have embarked on that journey with me. And for those who have done that with me, not all of them have actually implemented, kind of that definition of the individual types of contributions you can make so that we can do that kind of automated acknowledgment of the work.&nbsp;</p>\n\n\n\n<p>[00:06:40] (Music interlude)&nbsp;</p>\n\n\n\n<p>[00:06:47] <strong>Josepha:</strong> Which brings us now to our small list of big things. </p>\n\n\n\n<p>First on our list is WordPress 6.6. It&#8217;s our next major release. There are still a few volunteer roles that are available. I think documentation lead is one. So, if you are the sort of folk who just loves to write the docs, it&#8217;s been a while since you have done that for the WordPress project, with the WordPress project. That&#8217;s a great opportunity for you to kind of dip your toe in and see what&#8217;s going on in the world of WordPress. </p>\n\n\n\n<p>[00:07:15] <strong>Josepha:</strong> The second thing on our list is a minor release that actually came out last week. It&#8217;s a maintenance release, but it&#8217;s one of those where it&#8217;s really important to get upgraded and make sure that you have the latest security and maintenance releases on all of your sites that are in production.</p>\n\n\n\n<p>The third thing on our list is about Openverse. Openverse is now offering a new way to explore our collection. We&#8217;ve got over 800 million images and audio files in there. And so, the collection search makes it easier to view works that are belonging to an individual tag, creator, or source. It just kind of helps you filter it out a little bit more so that there are more decisions than there are options available in there.</p>\n\n\n\n<p>And the fourth thing on my list is that the WordCamp Europe 2024 schedule has been released. We&#8217;ll be talking a bit more about this event as we get closer and closer to it. We are racing our way. It&#8217;s like a month away as we go. So take a look, plan your activities, and come and check out our community.</p>\n\n\n\n<p>[00:08:16] <strong>Josepha:</strong> And that, my friends, is your small list of big things. Don&#8217;t forget to follow us on your favorite podcast app or subscribe directly on WordPress.org/news. You&#8217;ll get a friendly reminder whenever there&#8217;s a new episode. If you liked what you heard today, share it with a fellow WordPresser. Or, if you had questions about what you heard, you can share those with me at WPBriefing@WordPress.org. I&#8217;m your host, Josepha Haden Chomphosy. Thanks for tuning in today for the WordPress Briefing, and I&#8217;ll see you again in a couple of weeks.&nbsp;</p>\n\n\n\n<p>[00:08:44] (Music outro)&nbsp;</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17253\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"WordPress 6.5.3 Maintenance Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://wordpress.org/news/2024/05/wordpress-6-5-3-maintenance-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 May 2024 16:42:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=17246\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:338:\"WordPress 6.5.3 is now available! This minor release features 12 bug fixes in Core and 9 bug fixes for the block editor. You can review a summary of the maintenance updates in this release by reading the Release Candidate announcement. WordPress 6.5.3 is a short-cycle release. The next major release will be version 6.6 planned [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Aaron Jorbin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7679:\"\n<h2 class=\"wp-block-heading\">WordPress 6.5.3 is now available!</h2>\n\n\n\n<p>This minor release features <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;milestone=6.5.3&amp;group=status&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;col=keywords&amp;order=priority\">12 bug fixes in Core</a> and <a href=\"https://github.com/WordPress/gutenberg/pull/61299\">9 bug fixes for the block editor</a>. You can review a summary of the maintenance updates in this release by reading the <a href=\"https://make.wordpress.org/core/2024/05/02/wordpress-6-5-3-rc1-is-now-available/\">Release Candidate announcement</a>.</p>\n\n\n\n<p>WordPress 6.5.3 is a short-cycle release. The next major release will be <a href=\"https://make.wordpress.org/core/6-6/\">version 6.6</a> planned for July 2024.</p>\n\n\n\n<p>If you have sites that support automatic background updates, the update process will begin automatically.</p>\n\n\n\n<p>You can <a href=\"https://wordpress.org/wordpress-6.5.3.zip\">download WordPress 6.5.3 from WordPress.org</a>, or visit your WordPress Dashboard, click âUpdatesâ, and then click âUpdate Nowâ.</p>\n\n\n\n<p>For more information on this release, please <a href=\"https://wordpress.org/support/wordpress-version/version-6-5-3\">visit the HelpHub site</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Thank you to these WordPress contributors</h2>\n\n\n\n<p class=\"is-style-default\">This release was led by <a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a> and <a href=\"https://profiles.wordpress.org/grantmkin/\">Grant M. Kinney</a>.</p>\n\n\n\n<p class=\"is-style-default\">WordPress 6.5.3 would not have been possible without the contributions of the following people. Their asynchronous coordination to deliver maintenance fixes into a stable release is a testament to the power and capability of the WordPress community.</p>\n\n\n\n<p class=\"is-style-wporg-props-long\"><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/adamsilverstein\">Adam Silverstein</a>, <a href=\"https://profiles.wordpress.org/adrianduffell\">adrianduffell</a>, <a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>, <a href=\"https://profiles.wordpress.org/alanfuller\">Alan Fuller</a>, <a href=\"https://profiles.wordpress.org/anlino\">Anders NorÃ©n</a>, <a href=\"https://profiles.wordpress.org/oandregal\">AndrÃ©</a>, <a href=\"https://profiles.wordpress.org/afercia\">Andrea Fercia</a>, <a href=\"https://profiles.wordpress.org/azaozz\">Andrew Ozz</a>, <a href=\"https://profiles.wordpress.org/andrewserong\">Andrew Serong</a>, <a href=\"https://profiles.wordpress.org/afragen\">Andy Fragen</a>, <a href=\"https://profiles.wordpress.org/annezazu\">annezazu</a>, <a href=\"https://profiles.wordpress.org/dextorlobo\">Arun Sharma</a>, <a href=\"https://profiles.wordpress.org/aslamdoctor\">Aslam Doctor</a>, <a href=\"https://profiles.wordpress.org/benlk\">Ben Keith</a>, <a href=\"https://profiles.wordpress.org/britner\">Ben Ritner &#8211; Kadence WP</a>, <a href=\"https://profiles.wordpress.org/bernhard-reiter\">bernhard-reiter</a>, <a href=\"https://profiles.wordpress.org/ironprogrammer\">Brian Alexander</a>, <a href=\"https://profiles.wordpress.org/poena\">Carolina Nymark</a>, <a href=\"https://profiles.wordpress.org/costdev\">Colin Stewart</a>, <a href=\"https://profiles.wordpress.org/CookiesForDevo\">CookiesForDevo</a>, <a href=\"https://profiles.wordpress.org/colorful-tones\">Damon Cook</a>, <a href=\"https://profiles.wordpress.org/talldanwp\">Daniel Richards</a>, <a href=\"https://profiles.wordpress.org/darerodz\">darerodz</a>, <a href=\"https://profiles.wordpress.org/davecpage\">Dave Page</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/justlevine\">David Levine</a>, <a href=\"https://profiles.wordpress.org/DrewAPicture\">Drew Jaynes</a>, <a href=\"https://profiles.wordpress.org/ellatrix\">Ella</a>, <a href=\"https://profiles.wordpress.org/kebbet\">Erik</a>, <a href=\"https://profiles.wordpress.org/evanltd\">evanltd</a>, <a href=\"https://profiles.wordpress.org/flixos90\">Felix Arntz</a>, <a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>, <a href=\"https://profiles.wordpress.org/grantmkin\">Grant M. Kinney</a>, <a href=\"https://profiles.wordpress.org/gziolo\">Greg ZiÃ³Åkowski</a>, <a href=\"https://profiles.wordpress.org/isabel_brison\">Isabel Brison</a>, <a href=\"https://profiles.wordpress.org/macmanx\">James Huff</a>, <a href=\"https://profiles.wordpress.org/jason_the_adams\">Jason Adams</a>, <a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/JeffPaul\">Jeffrey Paul</a>, <a href=\"https://profiles.wordpress.org/jeherve\">Jeremy Herve</a>, <a href=\"https://profiles.wordpress.org/luminuu\">Jessica Lyschik</a>, <a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>, <a href=\"https://profiles.wordpress.org/joemcgill\">Joe McGill</a>, <a href=\"https://profiles.wordpress.org/jordesign\">jordesign</a>, <a href=\"https://profiles.wordpress.org/jorgefilipecosta\">Jorge Costa</a>, <a href=\"https://profiles.wordpress.org/verygoode\">Joshua Goode</a>, <a href=\"https://profiles.wordpress.org/kevin940726\">Kai Hao</a>, <a href=\"https://profiles.wordpress.org/kevinwhoffman\">Kevin Hoffman</a>, <a href=\"https://profiles.wordpress.org/khokansardar\">Khokan Sardar</a>, <a href=\"https://profiles.wordpress.org/luisherranz\">luisherranz</a>, <a href=\"https://profiles.wordpress.org/mmaattiiaass\">Matias Benedetto</a>, <a href=\"https://profiles.wordpress.org/webdevmattcrom\">Matt Cromwell</a>, <a href=\"https://profiles.wordpress.org/devsahadat\">Md Sahadat Husain</a>, <a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>, <a href=\"https://profiles.wordpress.org/narenin\">Narendra Sishodiya</a>, <a href=\"https://profiles.wordpress.org/ntsekouras\">Nik Tsekouras</a>, <a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/ramonopoly\">ramonopoly</a>, <a href=\"https://profiles.wordpress.org/roytanck\">Roy Tanck</a>, <a href=\"https://profiles.wordpress.org/salcode\">Sal Ferrarello</a>, <a href=\"https://profiles.wordpress.org/mikachan\">Sarah Norris</a>, <a href=\"https://profiles.wordpress.org/SergeyBiryukov\">Sergey Biryukov</a>, <a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>, <a href=\"https://profiles.wordpress.org/stevejonesdev\">Steve Jones</a>, <a href=\"https://profiles.wordpress.org/tomjcafferkey\">Tom Cafferkey</a>, <a href=\"https://profiles.wordpress.org/nestea29950\">WilliamG</a>, <a href=\"https://profiles.wordpress.org/yguyon\">Yannis Guyon</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">How to contribute</h2>\n\n\n\n<p>To get involved in WordPress core development, head over to Trac, <a href=\"https://core.trac.wordpress.org/report/6\">pick a ticket</a>, and join the conversation in the <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> and <a href=\"https://wordpress.slack.com/archives/C06U06K50Q5\">#6-6-release-leads</a> channels. Need help? Check out the <a href=\"https://make.wordpress.org/core/handbook/\">Core Contributor Handbook</a>.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Thanks to <a href=\"https://wordpress.slack.com/team/UGP7D7TBP\">@grantmkin</a>, </em><a href=\'https://profiles.wordpress.org/angelasjin/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>angelasjin</a><em>, </em>and <a href=\'https://profiles.wordpress.org/jeffpaul/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>jeffpaul</a><em> for proofreading.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17246\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:61:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"WP Briefing: Episode 78: Guided Growth: Cultivating Contributors Through Mentorship\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:104:\"https://wordpress.org/news/2024/04/episode-78-guided-growth-cultivating-contributors-through-mentorship/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 29 Apr 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Podcast\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"wp-briefing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://wordpress.org/news/?post_type=podcast&p=17229\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:378:\"Explore the transformative world of the WordPress Contributor Mentorship Program with guest host Angela Jin and special guest and sponsored contributor Hari Shanker. Whether you\'re a long-time WordPress enthusiast or new to the scene, this episode is packed with insights, stories, and tips to help you engage more deeply with one of the most passionate open source communities.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:53:\"https://wordpress.org/news/files/2024/04/Enhanced.mp3\";s:6:\"length\";s:1:\"0\";s:4:\"type\";s:0:\"\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:23988:\"\n<p>Explore the transformative world of the WordPress Contributor Mentorship Program with guest host Angela Jin and special guest and sponsored contributor Hari Shanker. Whether you&#8217;re a long-time WordPress enthusiast or new to the scene, this episode is packed with insights, stories, and tips to help you engage more deeply with one of the most passionate open source communities.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Credits</h2>\n\n\n\n<p>Guest host: <a href=\"https://profiles.wordpress.org/angelasjin/\">Angela Jin</a><br>Guest speaker: <a href=\"https://profiles.wordpress.org/harishanker/\">Hari Shanker</a><br>Editor:&nbsp;<a href=\"https://profiles.wordpress.org/dustinhartzler/\">Dustin Hartzler</a><br>Logo:&nbsp;<a href=\"https://profiles.wordpress.org/javiarce/\">Javier Arce</a><br>Production:&nbsp;<a href=\"https://profiles.wordpress.org/bjmcsherry/\">Brett McSherry</a>&nbsp;and&nbsp;<a href=\"https://profiles.wordpress.org/eidolonnight/\">Nicholas Garofalo</a><br>Song: Fearless First by Kevin MacLeod</p>\n\n\n\n<h2 class=\"wp-block-heading\">Show Notes</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://wordpress.org/5\">Five for the Future</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/handbook/contributor-day/contributor-working-group/contributor-mentorship-program-for-wordpress/\" target=\"_blank\" rel=\"noreferrer noopener\">About the Contributor Mentorship Program</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/handbook/contributor-day/contributor-working-group/contributor-mentorship-program-for-wordpress/contributor-mentorship-program-cohorts/\" target=\"_blank\" rel=\"noreferrer noopener\">Details of Mentorship Program Cohorts</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/2024/04/08/wordpress-contributor-mentorship-2024-q1-cohort-graduates/\" target=\"_blank\" rel=\"noreferrer noopener\">Mentorship Program Cohort 2 Graduation Post</a> &#8211; Express interest in the next cohort by&nbsp;leaving comment or sending a message to @harishanker in the <a href=\"https://make.wordpress.org/chat/\">Making WordPress Slack</a></li>\n\n\n\n<li><strong>Small List of Big Things</strong>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/support/2024/04/brainstorming-a-support-team-contributor-ladder/\" target=\"_blank\" rel=\"noreferrer noopener\">Brainstorming a Support Team Contributor Ladder</a>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/updates/2019/06/17/observations-on-wordpress-contributor-team-structure/\">Observations on WordPress Contributor Team Structure</a></li>\n</ul>\n</li>\n\n\n\n<li><a href=\"https://wordpressfoundation.org/news/2024/kim-parsell-2024/\" target=\"_blank\" rel=\"noreferrer noopener\">Apply for the Kim Parsell Memorial Scholarship for WordCamp US 2024</a></li>\n\n\n\n<li>Upcoming WordPress events:\n<ul class=\"wp-block-list\">\n<li><a href=\"https://europe.wordcamp.org/2024/\">WordCamp Europe 2024</a>\n<ul class=\"wp-block-list\">\n<li><a href=\"https://europe.wordcamp.org/2024/tickets/\">Tickets</a></li>\n</ul>\n</li>\n\n\n\n<li>Find upcoming events in your area on <a href=\"https://events.wordpress.org/\">events.WordPress.org</a></li>\n</ul>\n</li>\n</ul>\n</li>\n\n\n\n<li>Have a question you&#8217;d like answered? Submit them to&nbsp;<a href=\"mailto:wpbriefing@WordPress.org\">WPBriefing@WordPress.org</a>.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Transcript</h2>\n\n\n\n<span id=\"more-17229\"></span>\n\n\n\n<p>[00:00:00] <strong>Angela:</strong> Hello, everyone, and welcome to the WordPress Briefing, the podcast where you can catch quick explanations of the ideas behind the WordPress open source project, some insights into the community that supports it, and get a small list of big things coming up in the next two weeks. I am your guest host, Angela Jin.</p>\n\n\n\n<p>Let&#8217;s go!&nbsp;</p>\n\n\n\n<p>[00:00:30] (Intro Music)&nbsp;</p>\n\n\n\n<p>[00:00:40] <strong>Angela:</strong> I am delighted to be guest hosting this episode of the WordPress Briefing and to talk about the Contributor Mentorship Program, a community-driven initiative in the WordPress space that is proving to really support contributor journeys. And joining me today is special guest, Hari Shanker, Five for the Future Program Manager. Welcome, Hari!</p>\n\n\n\n<p>[00:01:02] <strong>Hari:</strong> Thank you, Angela. Excited to be here.</p>\n\n\n\n<p>[00:01:04] <strong>Angela:</strong> Now, before we dive into the Contributor Mentorship Program, can you first tell me a bit about yourself? I&#8217;d love to know a bit more about your role as Five for the Future Program Manager.</p>\n\n\n\n<p>[00:01:16] <strong>Hari:</strong> Sure. So, my name is Hari Shanker. I live in India in a city called Kochi. And I&#8217;d like to share some context to explain what I do. I am a sponsored contributor working full-time on WordPress, and I have been contributing primarily to the WordPress Community Team full-time since April 2020, where I am a Community Program Manager, formerly known as a Super Deputy.</p>\n\n\n\n<p>Since September 2022, I have been working exclusively on projects that bolster the WordPress contributor experience. A key part of this work is my role as the Program Manager for the Five for the Future program, where my day-to-day work involves supporting and empowering companies and individuals that have pledged a part of their time to contribute to WordPress.</p>\n\n\n\n<p>[00:02:00] <strong>Hari:</strong> In parallel, I also lead the Contributor Working Group of the WordPress Community Team, which has the goal of making the contributor experience in WordPress the best it can be. Our recent focus has been on running an experimental contributor mentorship program as well.Â </p>\n\n\n\n<p>[00:02:16] <strong>Angela:</strong> Excellent. Thank you. So, I was recently at Open Source Summit, and figuring out funding and commitments to projects was a very hot topic. And people were really interested in Five for the Future. And so, Hari, would you mind giving us a quick overview of what Five for the Future is, and how it aims to support the WordPress open source project?</p>\n\n\n\n<p>[00:02:44] <strong>Hari:</strong> Absolutely. The Cofounder of WordPress, Matt Mullenweg, launched Five for the Future in 2014 as a call to action for organizations and individuals who have benefited from WordPress, either the CMS or the community, to contribute up to 5 percent of their resources to the continued success of the WordPress project.</p>\n\n\n\n<p>[00:03:03] <strong>Hari:</strong> In 2019, this idea was formalized as a program with a pledging page that lives in the URL WordPress.org/five. Right now, this program attempts to foster generous collaboration towards the long-term health and stability of our project for the future. So, like any large and successful open source project, WordPress has a lot of big goals and tasks, not all of which can be accomplished by volunteers in that available time.</p>\n\n\n\n<p>Here&#8217;s where sponsored contributors come in. Sponsored contributors have more time, availability, and bandwidth to make an impact on a lot of these tasks. They also work on some routine but important administrative and housekeeping tasks that are essential to keep the project running smoothly. At this time, the program has 868 contributors from 183 companies, who have pledged 7,722 hours of contribution time per week for the program. I can also share that roughly 70% of contribution activity in WordPress is coming from these sponsored contributors. That is the Five for the Future program in brief.</p>\n\n\n\n<p>[00:04:15] <strong>Angela:</strong> Thanks, Hari. That&#8217;s incredible that so much of our contribution comes through sponsored time and clearly is very necessary to keep the WordPress open source project running. Wonderful. All right, well, I would love to dig into the Contributor Mentorship Program. Can you tell us a bit more about how this came to be? What is the Contributor Mentorship Program?</p>\n\n\n\n<p>[00:04:41] <strong>Hari:</strong> Oh, absolutely. It is one of my favorite programs and one of the best things that I&#8217;ve worked on personally. So, the Contributor Mentorship Program aims to onboard new contributors to WordPress by providing them one-on-one and cohort-based mentorship for a period of typically four to six weeks. The mentorship program typically coincides a major WordPress release.</p>\n\n\n\n<p>[00:05:04] <strong>Hari:</strong> And the idea behind the program is to help new contributors kickstart their WordPress contributor journey by providing them an in-depth overview of the WordPress project as well. To talk a bit about how this started, it all began in 2022-2023 when I started researching on the WordPress contributor experience. I discovered that there were gaps in the onboarding experience for new contributors. And I did some research on how we can solve this issue.</p>\n\n\n\n<p>Now, while those gaps can be fixed by improving the overall WordPress contributor onboarding experience through technical changes or changes in the program. Mentorship really stood out as an excellent solution to solve the problem. Based on my discovery from this research, I worked on revitalizing the WordPress Contributor Working Group of the Community Team. And together, our group we started working on building a mentorship program. We did a few months of collaborative discussions and brainstorming. And as a result, the group put together the idea for a pilot cohort-based mentorship program, which paired up 13 new contributors as mentees with one mentor each. The cohort worked together for four weeks, and 11 of these mentees graduated after making impactful contributions to the project, with over half of the cohort staying on to make long-term contributions. In fact, we just wrapped up the second cohort of the program in February 2024, which had 52 participants, of which 44 graduated from the program.</p>\n\n\n\n<p>[00:06:34] <strong>Angela:</strong> Amazing. Congratulations. And I speaking just for myself, I know how important mentorship was to, to a lot of my journeys, both within WordPress and outside of, and so I think it&#8217;s wonderful that we&#8217;re able to bring mentorship to this space. What sort of benefits are there to participating in this program, either as a new WordPress contributor or as a mentor?&nbsp;</p>\n\n\n\n<p>[00:07:04] <strong>Hari:</strong> There&#8217;s a bunch of benefits for both new contributors and mentors in this program, starting with new contributors. First and foremost, new participants in this program they get to kick off their WordPress contributor journey by making initial contributions. So, in my mind, the biggest benefit that they get is they get a chance to actually make their first contributions in the area of their choice with help from a mentor. The other main benefit that I see is that these mentees or new contributors. They get to learn a lot about the WordPress project and how it works. They get to learn about the WordPress release process broadly. And in short, participants in this program also get a chance to network with and learn from experienced WordPress contributors.</p>\n\n\n\n<p>And finally, this program is a great opportunity for mentees or new contributors to pick up a lot of valuable skills that they can use in the real world. For mentors, they also get a lot of benefits from this program. In fact, to share another anecdote, some of our mentors they contributed for the first time to WordPress core in the last cohort.</p>\n\n\n\n<p>[00:08:14] <strong>Hari:</strong> So, that is also something that they also get to learn, which means mentors also get to learn new skills when they be a part of this program. So, for mentors, even they get to enhance their skills, they get to expand the network within the WordPress community, but in my mind, the biggest benefit that they gain is they gain fulfillment from guiding new contributors. And personally, as a mentor myself, it&#8217;s one of the most valuable thing that you can gain from such a program. That feeling of belonging, that feeling of, you know, fostering sustainability and innovation in the project. I also feel that mentoring new contributors is a great way to bolster your leadership and communication skills, which is extremely valuable in any professional context.</p>\n\n\n\n<p>[00:08:54] <strong>Angela:</strong> Absolutely. I definitely see that being able to share your experience and mentor others is a really valuable way to help the next generation of WordPressers be successful in our space. Now, you&#8217;ve talked a bit about what results you&#8217;re seeing from this program, and it&#8217;s really exciting to see that so many mentees are successfully graduating from this program. I&#8217;d love to hear more about the impact and results that you&#8217;re seeing from the mentorship program. Could you give us more details there?</p>\n\n\n\n<p>[00:09:32] <strong>Hari:</strong> Absolutely. So, I shared some numbers earlier. We had 11 mentees out of 13 graduating from the 2023 cohort and 44 outta 52 mentees from the 2024 Q1 cohort graduating. From the first cohort we have six of these mentees continuing to make impactful contributions to the project, but we have more encouraging results from the second cohort, in fact. So, ten of our mentees in the second cohort got props for contributing to WordPress 6.5, and one of our mentees was a noteworthy contributor. That&#8217;s about 22% of all the mentees. Fourteen mentees from the latest cohort, which is 31%, they have committed to join the WordPress 6.6 release squad. And the program actually gave eight new core contributors to the project, which includes mentors, as I mentioned earlier.</p>\n\n\n\n<p>[00:10:21] <strong>Hari:</strong> We did pre and post-cohort surveys, and the results are very interesting. I can definitely share some numbers here. So, we had a question on contributor familiarity. The familiarity of contribution for new contributors went up from 53% to 80%, that&#8217;s around 26% increase. The contribution confidence went from 57% to 82%, which is around 28%-29%. We asked if the mentees how many of these mentees were satisfied by the program. We heard that 88% of all the mentees were satisfied. 80% of mentees achieved their personal goals as part of the program. A key part of the program experience was that we asked mentees to create contribution plans to make future contributions.</p>\n\n\n\n<p>[00:11:06] <strong>Hari:</strong> 62% of our mentees actually made a future contribution plan. So which means, which is a 30, 60, 90-day plan. So, these mentees they&#8217;re gonna follow a plan to contribute to WordPress for the next three months. Finally, we also created a ton of learning materials for these mentees, and we are in the process of releasing them. So these are, most of these are videos, so we plan to release them in WordPress or TV and in the Learn WordPress platform. So, in my mind, seeing these mentees out in the world making impactful contributions that is the biggest impact that I&#8217;m seeing. So, having them in the project as long-term contributors. That is, in my mind, one of the biggest impacts that we&#8217;ve had from this program.</p>\n\n\n\n<p>[00:11:46] <strong>Angela:</strong> Yeah, that&#8217;s really incredible to see that new contributors to WordPress, upon joining this program, able to better navigate this vast ecosystem and make important contributions to our space. And that they&#8217;ve made these connections, so they are sticking around and staying with us and continuing to help us build WordPress. That&#8217;s incredible.&nbsp;</p>\n\n\n\n<p>[00:12:14] <strong>Angela:</strong> Now, I understand that between the first cohort and the second cohort, the Contributor Working Group made some important updates and iterated on the cohort itself. And one of the big changes, I understand, was to design cohorts around contributor projects. I&#8217;m curious now that we&#8217;ve talked about how fantastic this program is. Are there plans for future cohorts, and what might those cohorts look like?</p>\n\n\n\n<p>[00:12:44] <strong>Hari:</strong> Absolutely. So, we have received a lot of interest in future cohorts. So, our working group just did a chat last week, and there was overwhelming positive interest and from all our working group members and other participants saying that we would love to be in a future cohort. So, short answer, yes, we will have a ton of these cohorts going forward. And we are, in fact, hosting a new cohort alongside WordPress 6.7. In October-November, 2024. And we will most likely continue to host at least one mentorship cohort every year. Ideally two, but I&#8217;m just saying one to make sure that we are sustainable. It is hard to predict how future cohorts will look like, but based on all the discussions our working group has had, I can definitely tell you how the next cohort is going to look like.</p>\n\n\n\n<p>[00:13:35] <strong>Hari:</strong> So, as per current plans, we will have around 20 to 30 mentees supported by mentors. And the cohort will most likely start early on in the 6.7 release process. The idea is that we would like our mentees to be more deeply involved in the 6.7 release as early as possible. We also plan to have a lot more learn-up sessions in the next cohort.</p>\n\n\n\n<p>One feedback that we heard was our mentees really enjoyed some of the learn-up sessions, and they would like these sessions to be scheduled in advance as much as possible so that they can attend as many of them as possible. So, more learn-up sessions. </p>\n\n\n\n<p>[00:14:14] <strong>Hari:</strong> And finally, you mentioned projects when you spoke of the latest cohort. We are going to double down on projects in the next cohort. So the hope is to have a host of projects for folks to work on and, ideally, have all mentees work on some project or the other. So, we had projects as an experiment for the earlier cohort. Some mentees did work on projects, while some they were broadly contributing. So, ideally, for the next cohort, every mentee in the program will be a part of some project or the other. It could be a small one. It could be a big one, but there will be some project of some sort for every mentee in the program, ideally. And finally, some contributors in our cohort, they received a scholarship to participate in the last cohort. We hope to expand that. We hope to provide more opportunities for scholarship for contributors.</p>\n\n\n\n<p>[00:15:05] <strong>Hari:</strong> I&#8217;m not sure how viable it is, but we did see that the folks who received scholarship, they got a chance to contribute more. So we would ideally like to provide more opportunities for scholarship, especially for folks from underrepresented backgrounds, so that they can contribute to WordPress and, you know, upskill as part of this program.</p>\n\n\n\n<p>[00:15:23] <strong>Angela:</strong> Fantastic. Well, hopefully, we have convinced our listeners today to get involved in the Contributor Mentorship Program. And so, if somebody wanted to get involved, either as a mentee or a mentor, how should they go about doing so?</p>\n\n\n\n<p>[00:15:42] <strong>Hari:</strong> That&#8217;s a great question. We have not opened up signups for mentors and mentees for the next cohort yet. As I mentioned, it&#8217;s going to happen later this year. However, those interested in the next cohort of the program can comment on the post. I think we can share the link in the show notes. We just published a post announcing the graduation of our mentees, and we had asked folks who are interested in joining the next cohort comment there.</p>\n\n\n\n<p>[00:16:07] <strong>Hari:</strong> So if you&#8217;re interested in joining the next cohort, either as a mentor or a mentee. You can comment on that post. Alternatively, you can also DM me. If you&#8217;re not comfortable commenting in a public space, my name is Hari Shanker. I am Hari Shanker, which is H-A-R-I-S-H-A-N-K-E-R. That&#8217;s my username in the Make WordPress Slack. You can DM me there expressing your interest, and I will make sure that we send you the call for interest form when it&#8217;s published.</p>\n\n\n\n<p>Additionally, and this is especially to all the mentor applicants, we have a Contributor Working Group, which meets every third Thursday of the month in the Community Team channel on a text chat. It&#8217;s called a mentorship chat. It happens every month, and you can find a link to it in the Make WordPress meetings, P2 blog. So, if you&#8217;re interested in being a mentor, or if you&#8217;re interested in building the Contributor Mentorship Program, or contributing to the Contributor Mentorship Program, I would invite you to join our chat. So, the next chat is being held in May. Please join our next chat. That&#8217;s also a great way to contribute to this program, especially if you are interested in being a mentor.&nbsp;</p>\n\n\n\n<p>[00:17:10] <strong>Angela:</strong> Wonderful. Thank you so much for joining me today, Hari. It&#8217;s been a pleasure.</p>\n\n\n\n<p>[00:17:16] <strong>Hari:</strong> Thank you. It&#8217;s been an honor, and thank you for inviting me to be a part of this program.&nbsp;</p>\n\n\n\n<p>[00:17:19]&nbsp;(Music interlude)&nbsp;</p>\n\n\n\n<p>[00:17:27] <strong>Angela:</strong> And now it is time for our small list of big things. We&#8217;ve got three things for you this week. </p>\n\n\n\n<p>The first is a proposal to explore the Support Team contributor ladder. If you are not familiar with the concept of the contributor ladder, it is based on the five stages of volunteering, which examines how a volunteer gets onboarded and steps into progressive roles. By thinking through the contributor ladder, Make WordPress teams are able to improve onboarding, engagement, and connection with contributors and generally improve the health of their team. If this is of interest to you, we have a great overview post about the contributor ladder, and you can see the discussion in action over on the Support Team.&nbsp;</p>\n\n\n\n<p>[00:18:14] <strong>Angela:</strong> Second, is that the WordPress Foundation has just announced the Kim Parcell Memorial Scholarship for 2024. This scholarship is in honor of Kim Parcell, an incredible long-time contributor, and is awarded to a current WordPress contributor who is a woman, has not previously attended WordCamp US, and requires financial assistance to attend this year&#8217;s event.&nbsp;The scholarship will provide travel assistance for the recipient to attend WordCamp US this year in Portland, Oregon, and covers travel from your home city, hotel, and your ticket to the event. The application is open through May 30th, and you can apply on the WordPress Foundation page.&nbsp;</p>\n\n\n\n<p>Third is a reminder of our next big WordPress event, WordCamp Europe, which will be in beautiful Torino, Italy, June 13th through the 15th. You can still get tickets on their website. If you can&#8217;t make it to Italy, never fear. This time of year sees a good number of WordPress events around the world, and they are a great way to connect with WordPress friends and hear all about the latest and greatest in WordPress. You can go find upcoming events on events.WordPress.org to see what events are happening in your area. If there isn&#8217;t a WordPress event near you, you can become an organizer and start hosting events locally.&nbsp;</p>\n\n\n\n<p>[00:19:42] <strong>Angela:</strong> And that, friends, is your small list of big things. Don&#8217;t forget to follow us on your favorite podcast app. Or subscribe directly on WordPress.org/news. You&#8217;ll get a friendly reminder whenever there&#8217;s a new episode. If you liked what you heard today, share it with a fellow WordPresser, or if you had questions about what you heard, you can share those by emailing WPBriefing@WordPress.org. I am your guest host, Angela Jin. Thanks so much for tuning in today for the WordPress Briefing. In a couple of weeks, Josepha will be back as your regular host for the next episode.&nbsp;</p>\n\n\n\n<p>[00:20:21] (Music outro)&nbsp;</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17229\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"How WordPress Is Creating a Faster Web\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://wordpress.org/news/2024/04/how-wordpress-is-creating-a-faster-web/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 15 Apr 2024 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:11:\"Performance\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:7:\"Updates\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=17208\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:190:\"WordPress\'s massive reach of over 40% of the web comes with a similarly large responsibility. Read about what the WordPress project is doing to enhance performance for its users and the web.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Felix Arntz\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6801:\"\n<p>Today, WordPress powers <a href=\"https://w3techs.com/technologies/overview/content_management\">more than 40% of the web</a>. Thatâs a massive reachâone that comes with a similarly large responsibility. With so many people using the CMS, the WordPress community should always consider strategies for improving the visitor experience. This is where website performance plays a crucial role.</p>\n\n\n\n<p>How fast a web page loads, how quickly a page reacts when you click a button, or how smoothly it scrolls can all significantly impact the end-user experience. A more performant site can lead to <a href=\"https://web.dev/case-studies/vitals-business-impact\">higher reader engagement and more conversions</a>. Thankfully, over the past few years, the WordPress project has made major performance improvements across the board for the core platform, plugins, and themes.</p>\n\n\n\n<p>Many enhancements are available out of the box, with no configuration required. They improve the website frontend&#8217;s performanceâthe part visitors seeâand various parts of the administrative experience, such as the editor.</p>\n\n\n\n<p>Hereâs a partial list of performance upgrades from the past year:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>WordPress 6.3 brought several <a href=\"https://make.wordpress.org/core/2023/09/19/analyzing-the-core-web-vitals-performance-impact-of-wordpress-6-3-in-the-field/\">enhancements to image loading</a>. This resulted in an improvement of up to 21% in loading time for any WordPress page with a hero image.</li>\n\n\n\n<li>WordPress 6.5 launched with a <a href=\"https://make.wordpress.org/core/2023/11/08/merging-performant-translations-into-core/\">more efficient translation engine</a>. In benchmark testing, it improved WordPress response time by 23% for all localized WordPress sites. <a href=\"https://wordpress.org/about/stats/\">More than 55% of all WordPress sites</a> worldwide use a language other than US English and would benefit from this enhancement.</li>\n\n\n\n<li>WordPress 6.5 also included several performance optimizations for the Block Editor, leading to <a href=\"https://github.com/WordPress/gutenberg/issues/57935\">5x faster typing processing and 2x faster load times</a> when creating or editing content in the site and post editors.</li>\n</ul>\n\n\n\n<p>In addition to the Core enhancements listed above, the WordPress project continues to work on several efforts that indirectly benefit the ecosystem&#8217;s performance.</p>\n\n\n\n<p>For instance, WordPress Core leverages <a href=\"https://codehealth.vercel.app/project/wordpress\">automated tooling for continuously monitoring its performance</a>, covering every product update. This helps measure new features&#8217; performance improvements and enables contributors to detect potential performance problems during the development of a new feature or release so any issues can be proactively addressed long before end users are affected. A project is currently underway to make the same tooling used by WordPress Core developers available to plugin and theme authors as well.</p>\n\n\n\n<p>Additionally, the new <a href=\"https://wordpress.org/plugins/plugin-check/\">WordPress plugin checker</a> allows checking any plugin for performance best practices, among other requirements and recommendations. The plugin checker should lead to more performance awareness in plugin authors and, eventually, faster plugins. If you develop plugins, consider integrating this tool into your development and testing workflow.</p>\n\n\n\n<p>Last but not least, WordPress 6.5 introduced the <a href=\"https://make.wordpress.org/core/2024/03/04/interactivity-api-dev-note/\">Interactivity API</a>, which is a technical foundation that facilitates more performant user interactions. This new infrastructure drastically simplifies the implementation of interactive website features and can even centrally control certain aspects of performance, keeping multiple independent plugins operating efficiently.</p>\n\n\n\n<p>These performance updates result from a collaborative effort from all corners of the community, including the <a href=\"https://make.wordpress.org/performance/handbook/about-the-team/\">WordPress Performance Team</a>. This team, founded in 2021, underscores the WordPress projectâs commitment to performance. And the results are substantial: Compared to a year ago, 8% more WordPress sites <a href=\"https://make.wordpress.org/core/2023/12/19/wordpress-performance-impact-on-core-web-vitals-in-2023/\">deliver good load time performance at scale</a>âsignificantly better than the overall webâs 5.5% load time improvement. The web is getting more performant, and WordPress is leading the way.</p>\n\n\n\n<p>WordPress contributors are determined to continue this trend by working on further performance iterations. Whether youâre a WordPress end user, administrator, site builder, or developer, you can contribute to this effort. Anyone can test the performance features before being released in Core through individual feature plugins. Each feature can be tested via the <a href=\"https://wordpress.org/plugins/performance-lab/\">Performance Lab plugin</a>, so please try them! Testing features early helps the team assess their impact and collect valuable feedback.</p>\n\n\n\n<p>Are you eager for more WordPress performance news and updates? Then check out the <a href=\"https://make.wordpress.org/performance/roadmap-2024/\">2024 performance roadmap</a>. Thanks to the entire community for your hard work. Not only does it ensure WordPressâ continued improvement and growth, but it benefits the entire open web.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Thank you to <a href=\'https://profiles.wordpress.org/annezazu/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>annezazu</a> <a href=\'https://profiles.wordpress.org/clarkeemily/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>clarkeemily</a> <a href=\'https://profiles.wordpress.org/tweetythierry/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>tweetythierry</a> <a href=\'https://profiles.wordpress.org/swissspidy/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>swissspidy</a> <a href=\'https://profiles.wordpress.org/westonruter/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>westonruter</a> <a href=\'https://profiles.wordpress.org/adamsilverstein/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>adamsilverstein</a> <a href=\'https://profiles.wordpress.org/joemcgill/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>joemcgill</a> for content review and <a href=\'https://profiles.wordpress.org/provenself/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>provenself</a> <a href=\'https://profiles.wordpress.org/dansoschin/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>dansoschin</a> for editorial review.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"17208\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:32:\"https://wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"14607090\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:12:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Thu, 13 Jun 2024 05:56:39 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:25:\"strict-transport-security\";s:12:\"max-age=3600\";s:6:\"x-olaf\";s:3:\"â\";s:13:\"last-modified\";s:29:\"Tue, 11 Jun 2024 16:26:15 GMT\";s:4:\"link\";s:63:\"<https://wordpress.org/news/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}}s:5:\"build\";s:14:\"20211221033300\";}', 'no');
