(4640, '_transient_feed_d117b5738fbd35bd8c0391cda1f2b5d9', 'a:4:{s:5:\"child\";a:1:{s:0:\"\";a:1:{s:3:\"rss\";a:1:{i:0;a:6:{s:4:\"data\";s:3:\"\n\n\n\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:7:\"version\";s:3:\"2.0\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:1:{s:7:\"channel\";a:1:{i:0;a:6:{s:4:\"data\";s:61:\"\n	\n	\n	\n	\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"WordPress Planet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"language\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"en\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress Planet - http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"item\";a:50:{i:0;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"Do The Woo Community: A Pre-Launch Chat with Jay Walsh at WooCommerce\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"https://dothewoo.io/?p=84147\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"https://dothewoo.io/a-pre-launch-chat-with-jay-walsh-at-woocommerce/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:118:\"Jay Walsh, Public Relations at WooCommerce and BobWP have a conversation about what Do the Woo means to the community.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 12 Jun 2024 08:02:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:174:\"HeroPress: Providing great value to WordPress without coding â Denna text finns Ã¤ven pÃ¥ svenska nedan â Ð­ÑÐ¾ ÑÑÑÐµ ÑÐ°ÐºÐ¶Ðµ ÐµÑÑÑ Ð½Ð° ÑÑÑÑÐºÐ¾Ð¼ Ð½Ð¸Ð¶Ðµ\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://heropress.com/?post_type=heropress-essays&p=6848\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:172:\"https://heropress.com/essays/providing-great-value-to-wordpress-without-coding/#utm_source=rss&utm_medium=rss&utm_campaign=providing-great-value-to-wordpress-without-coding\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:22927:\"<img width=\"1024\" height=\"512\" src=\"https://heropress.com/wp-content/uploads/2024/06/061124-min.jpg\" class=\"attachment-large size-large wp-post-image\" alt=\"Pull Quote: I want the WordPress community to become even stronger and more sustainable.\" />\nHere is Tobi reading his own story aloud.\n\n\n\n\n\n<p><a href=\"https://heropress.com/feed/#svenska\">Denna text finns Ã¤ven pÃ¥ svenska nedan.</a></p>\n\n\n\n<p><a href=\"https://heropress.com/feed/#russian\">Ð­ÑÐ¾ ÑÑÑÐµ ÑÐ°ÐºÐ¶Ðµ ÐµÑÑÑ Ð½Ð° ÑÑÑÑÐºÐ¾Ð¼ Ð½Ð¸Ð¶Ðµ.</a></p>\n\n\n\n<p>There are a lot of ways to contribute to WordPress, many of which require no coding skills. Here, Iâd like to share my journey into WordPress and what this project means to me.</p>\n\n\n\n<p><em>Who am I?</em></p>\n\n\n\n<p>Iâm Swedish but have been living abroad for the last 23 years. I like technology in general, IT and Telecom in particular. I love writing and do it regularly in three languages: English, Swedish, and Russian.</p>\n\n\n\n<p>Professionally, Iâve gained lot of experience over the last 30 years as Project Manager, Product Manager, and Change Manager, mainly in Telecom and IT. During this time, I have lived and worked in ten countries. Iâve been leading small and large teams, working both on-site and remotely, in positions with both system vendors and operator companies (startups, as well as large, mature companies). Iâve been doing both traditional âwaterfallâ projects, and leading Scrum teams.</p>\n\n\n\n<p>In parallel, between projects, Iâve also worked many years as a professional linguist (English, Swedish, and Russian).</p>\n\n\n\n<p><em>Discovering WordPress</em></p>\n\n\n\n<p>I started blogging in Russian on a different platform in early 2005. A couple of years later I picked up writing poetry and short form fiction in Swedish, publishing it initially on a specialized Swedish resource.</p>\n\n\n\n<p>In 2011, I decided to gather most of my writing in one place. I got me a domain, installed WordPress and built my own three-language web site. I still remember how magically easy it was to migrate my Russian blog from LiveJournal to WordPress already in 2011.</p>\n\n\n\n<p><em>Initial contribution to the WordPress eco-system</em></p>\n\n\n\n<p>For use on my own sites, I improved the Swedish and Russian translations of the theme I was using and shared these translations with the theme developer for other people to use.</p>\n\n\n\n<p><em>Contributing more actively</em></p>\n\n\n\n<p>Using WordPress was fun. Now and then I help friends and family setting up simple sites. I was gradually becoming more interested in participating in the making of WordPress as a way of giving back to the community. I happened to have some spare time available when WordPress 4.7 was being prepared. Being a professional translator, I quickly suggested several hundreds of strings for the Swedish translation and was quickly promoted to General Translation Editor for Swedish. Soon I was expanding and mentoring the Swedish translation team.</p>\n\n\n\n<p><em>But there was more to it</em></p>\n\n\n\n<p>As an experienced Project Manager and Change Manager, I strived to understand the fuller picture better, and helped fellow GTEs for other language teams to discuss and solve problems they encountered. Here, too, I was soon promoted to team representative and global mentor.</p>\n\n\n\n<p>Since then, Iâve been contributing in several ways: co-organizer of a WordCamp in Stockholm, co-organizer of several translation events, Support contributor (especially in the Swedish support forum), as speaker, and more.</p>\n\n\n\n<p>Recently, Iâve participated actively in discussions around improving âdiscoverabilityâ of contributing to WordPress and creating smoother on-boarding for new contributors. I also participated as mentor in the pilot cohorts of our new mentoring program for new contributors. This kind of building structure and improving processes come naturally to me, because of my professional experience and my interests in general.</p>\n\n\n\n<p>I want the WordPress community to become even stronger and more sustainable. Thereâs much more to be done, especially when it comes to building up strong local communities that can translate, train, popularize and support WordPress in many different languages and locations around the world.</p>\n\n\n\n<p>Iâd be enormously happy to contribute much more to these processes. A perfect solution would be to become a full-time sponsored contributor, where Iâd be fully able to bring big value. It may go the other way, too: If I get hired for some intensive project, I may not have time and energy for WordPress, even if contributing here brings me happiness and fulfillment.</p>\n\n\n\n<p>Tor-BjÃ¶rn (Tobi) Fjellner</p>\n\n\n<div class=\"kb-row-layout-wrap kb-row-layout-id6848_4286a0-c6 alignnone kt-row-has-bg wp-block-kadence-rowlayout\"><div class=\"kt-row-column-wrap kt-has-1-columns kt-row-layout-equal kt-tab-layout-inherit kt-mobile-layout-row kt-row-valign-top kb-theme-content-width\">\n\n<div class=\"wp-block-kadence-column kadence-column6848_c4c0da-d7\"><div class=\"kt-inside-inner-col\">\n<p><strong>You can start contributing to WordPress today:</strong></p>\n\n\n\n<p>There are more than 20 volunteer teams contributing to WordPress.</p>\n\n\n\n<p>For instance, there are teams that:</p>\n\n\n\n<ul>\n<li>translate WordPress to more than 60 language versions</li>\n\n\n\n<li>develop and maintain documentation (in several languages)</li>\n\n\n\n<li>create trainings and self-study material (in several languages)</li>\n\n\n\n<li>edit, subtitle, and publish video recordings of presentations</li>\n\n\n\n<li>organize meetups and WordPress conferences</li>\n\n\n\n<li>gather photos and other media files that are free to use on any site</li>\n\n\n\n<li>â¦ and much more</li>\n</ul>\n\n\n\n<p>Go to <a href=\"https://make.wordpress.org/contribute/\">https://make.wordpress.org/contribute/</a> to find which team suits you the best.</p>\n\n\n\n<p>You can also:</p>\n\n\n\n<ul>\n<li>See a list of the main teams at <a href=\"https://make.wordpress.org/\">https://make.wordpress.org/</a></li>\n\n\n\n<li>Register your personal forum account at <a href=\"https://login.wordpress.org/register?locale=en_US\">https://login.wordpress.org/register?locale=en_US</a>&nbsp;</li>\n\n\n\n<li>Search a WordPress event near you at <a href=\"https://events.wordpress.org/\">https://events.wordpress.org/</a>&nbsp;</li>\n</ul>\n</div></div>\n\n</div></div>\n\n\n<p class=\"kt-adv-heading6848_c1e170-ec wp-block-kadence-advancedheading\">Welcome!</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h1 id=\"svenska\" class=\"kt-adv-heading6848_83d9c3-1c wp-block-kadence-advancedheading\">Att tillfÃ¶ra stort vÃ¤rde till WordPress utan programmering</h1>\n\n\n\nHÃ¤r lÃ¤ser Tobi sjÃ¤lv sin berÃ¤ttelse pÃ¥ svenska.\n\n\n\n\n\n<p>Man kan bidra till WordPress pÃ¥ mÃ¥nga sÃ¤tt, och lÃ¥ngt ifrÃ¥n alla krÃ¤ver kunskaper i programmering. HÃ¤r vill jag berÃ¤tta om hur jag hittade fram till WordPress och vad projektet betyder fÃ¶r mig personligen.</p>\n\n\n\n<p><em>Vem Ã¤r jag?</em></p>\n\n\n\n<p>Jag Ã¤r frÃ¥n Sverige men bor utomlands sedan 23 Ã¥r. Jag gillar teknik i allmÃ¤nhet, framfÃ¶r allt IT och telekom. Jag Ã¤lskar att skriva och gÃ¶r det regelbundet pÃ¥ tre olika sprÃ¥k: engelska, svenska och ryska.</p>\n\n\n\n<p>Genom mina jobb har jag samlat pÃ¥ mig stor erfarenhet under de senaste 30 Ã¥ren som projektledare, produktchef och change manager, frÃ¤mst inom telekom och IT. Sammanlagt har jag bott och arbetat i tio lÃ¤nder. Jag har lett bÃ¥de smÃ¥ och stora team, arbetat direkt pÃ¥ plats och pÃ¥ distans, fÃ¶r bÃ¥de systemleverantÃ¶rer och telekomoperatÃ¶rer (bÃ¥de nystartade och etablerade operatÃ¶rer). Jag har bÃ¥de arbetat med traditionellt projektformat och lett Scrum-team.</p>\n\n\n\n<p>Mellan projekten, har jag ocksÃ¥ arbetat mÃ¥nga Ã¥r som professionell Ã¶versÃ¤ttare och redaktÃ¶r (pÃ¥ engelska, svenska och ryska).</p>\n\n\n\n<p><em>Hur jag upptÃ¤ckte WordPress</em></p>\n\n\n\n<p>Jag bÃ¶rjade blogga pÃ¥ ryska pÃ¥ en annan plattform i bÃ¶rjan av 2005. Ett par Ã¥r senare bÃ¶rjade jag skriva poesi och korta skÃ¶nlitterÃ¤ra texter pÃ¥ svenska, som jag i bÃ¶rjan publicerade pÃ¥ en specialiserad webbplats (poeter.se).</p>\n\n\n\n<p>ÃINSERT INTO `fountainlu_options` (`option_id`, `option_name`, `option_value`, `autoload`) VALUES
