(19, 1, '2020-07-06 06:52:21', '2020-07-06 06:52:21', 'If you want to talk to us, our contact number is 617-528-8672. You may reach us through the email <a href=\"mailto:Lmuiruri@fountainwisdom.org\">Lmuiruri@fountainwisdom.org</a> for our news feed and progress report, or talk to us through this message board. \r\n\r\n[form src=\"contactForm\"]', 'Contact Us', '', 'publish', 'closed', 'closed', '', 'nonprofit-organization-contact-us', '', '', '2020-08-14 16:14:54', '2020-08-14 16:14:54', '', 0, 'http://localhost/abuga/fountainlu/?page_id=19', 0, 'page', '', 0),
